window.PACTO.acts["reg-2021-2303"]={"label": "REGOLAMENTO (UE) 2021/2303 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2021/2303", "file": "ext-reg-2021-2303.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2021/2303/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e campo d’applicazione", "anchor": "art_1", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il presente regolamento istituisce un’Agenzia dell’Unione europea per l’asilo («l’Agenzia»). L’Agenzia sostituisce l’Ufficio europeo di sostegno per l’asilo (EASO), istituito con il regolamento (UE) n. 439/2010, e vi succede.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia contribuisce a garantire l’applicazione efficace ed uniforme, negli Stati membri, della legislazione dell’Unione in materia d’asilo rispettando pienamente i diritti fondamentali. L’Agenzia facilita e sostiene le attività degli Stati membri nell’attuazione del sistema europeo comune di asilo (CEAS), anche facendo sì che le valutazioni delle domande di protezione internazionale nell’Unione siano convergenti e coordinando e rafforzando la cooperazione pratica e lo scambio di informazioni.</p>\n<p class=\"oj-normal\">L’Agenzia migliora il funzionamento del CEAS anche attraverso il meccanismo di monitoraggio di cui all’articolo 14 e prestando assistenza operativa e tecnica agli Stati membri, in particolare nei casi in cui i loro sistemi di asilo e di accoglienza siano sottoposti a pressioni sproporzionate.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia costituisce un centro specializzato in virtù dell’indipendenza e della qualità scientifica e tecnica dell’assistenza fornita e delle informazioni raccolte e diffuse, della trasparenza delle sue procedure e delle modalità di funzionamento, della diligenza nell’espletare i compiti attribuitile e del supporto informatico necessario allo svolgimento del suo mandato.</p>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Compiti", "anchor": "art_2", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai fini dell’articolo 1, l’Agenzia svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilita, coordina e rafforza la cooperazione pratica e lo scambio di informazioni fra gli Stati membri sui loro sistemi di asilo e di accoglienza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">raccoglie e analizza informazioni di natura qualitativa e quantitativa sulla situazione dell’asilo e sull’attuazione del CEAS;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostiene gli Stati membri nell’assolvimento dei loro compiti e dei loro obblighi nel quadro del CEAS;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri nella formazione e, se del caso, fornisce formazione agli esperti degli Stati membri di tutte le amministrazioni e di tutti gli organismi giurisdizionali nazionali, così come delle autorità nazionali responsabili delle questioni attinenti all’asilo, anche attraverso l’elaborazione di un programma comune europeo di formazione in materia di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stila e aggiorna regolarmente le relazioni e altri documenti che forniscono informazioni sulla situazione nei paesi terzi interessati, compresi i paesi d’origine, a livello dell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e coordina reti europee d’informazione sui paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizza attività e coordina gli sforzi fra gli Stati membri per sviluppare analisi comuni sulla situazione nei paesi d’origine e note di orientamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce informazioni e analisi sui paesi terzi per quanto riguarda concetto di paese di origine sicuro e il concetto di paese terzo sicuro («concetti di paese sicuro»);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce un’efficace assistenza operativa e tecnica agli Stati membri, in particolare nei casi in cui i loro sistemi di asilo e di accoglienza siano sottoposti a pressioni sproporzionate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce un sostegno adeguato agli Stati membri nell’assolvimento dei loro compiti e dei loro obblighi a norma del regolamento (UE) n. 604/2013;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza nella ricollocazione o nel trasferimento di richiedenti o di beneficiari di protezione internazionale nell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costituisce e invia squadre di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costituisce un gruppo di riserva in materia d’asilo conformemente all’articolo 19, paragrafo 6 («gruppo di riserva in materia d’asilo»);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">acquisisce e predispone le necessarie attrezzature tecniche per le squadre di sostegno per l’asilo e gli esperti del gruppo di riserva in materia di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elabora norme operative, indicatori, orientamenti e migliori prassi riguardo all’attuazione del diritto dell’Unione in materia di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">invia funzionari di collegamento negli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora l’applicazione operativa e tecnica del CEAS allo scopo di aiutare gli Stati membri a migliorare l’efficienza dei loro sistemi di asilo e accoglienza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostiene gli Stati membri nella cooperazione con i paesi terzi nelle materie attinenti alla dimensione esterna del CEAS, anche mediante l’impiego di funzionari di collegamento nei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri nelle azioni relative al reinsediamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia svolge di propria iniziativa attività di comunicazione nei campi che rientrano nel suo mandato. Essa fornisce al pubblico informazioni precise ed esaustive sulle sue attività. L’Agenzia si astiene da attività di comunicazione che possano pregiudicare i compiti di cui al paragrafo 1 del presente articolo. Le attività di comunicazione sono svolte fatto salvo l’articolo 65 e conformemente ai pertinenti piani di comunicazione e divulgazione adottati dal consiglio d’amministrazione.</p>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Referenti nazionali per la comunicazione", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">Ciascuno Stato membro designa almeno un referente nazionale incaricato di comunicare con l’Agenzia in merito a tutte le questioni attinenti ai compiti di cui all’articolo 2.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Dovere di cooperare in buona fede e di scambiarsi informazioni", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia e le autorità nazionali responsabili per l’asilo e l’immigrazione e altri servizi competenti cooperano in buona fede.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Per adempiere ai compiti e agli obblighi ad esse conferiti dal presente regolamento, in particolare per quanto riguarda l’assolvimento dei compiti di cui all’articolo 2, l’Agenzia e le autorità nazionali responsabili per l’asilo e l’immigrazione e altri servizi competenti si scambiano tutte le informazioni necessarie in maniera tempestiva e precisa.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia lavora a stretto contatto con le autorità nazionali responsabili per l’asilo e l’immigrazione e con altri servizi competenti, così come con la Commissione. Svolge i propri compiti fermi restando quelli conferiti ad altri organismi, uffici e agenzie dell’Unione pertinenti. L’Agenzia collabora con detti organismi, uffici e agenzie, con le organizzazioni intergovernative, in particolare l’Alto commissario delle Nazioni Unite per i rifugiati (UNHCR), e con altre organizzazioni competenti previste dal presente regolamento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia organizza, promuove e coordina attività che consentano lo scambio di informazioni fra gli Stati membri, se del caso anche attraverso la costituzione di reti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Qualora, dopo aver invitato uno Stato membro a fornire all’Agenzia le informazioni necessarie per l’assolvimento dei suoi compiti a norma del presente regolamento, il direttore esecutivo ritenga che lo Stato membro interessato abbia sistematicamente omesso di farlo, riferisce tale circostanza al consiglio di amministrazione e alla Commissione.</p>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Analisi delle informazioni sulla situazione dell’asilo", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per fornire informazioni tempestive e affidabili agli Stati membri e individuare possibili rischi per i sistemi d’asilo e di accoglienza degli Stati membri, l’Agenzia raccoglie e analizza informazioni sulla situazione dell’asilo nell’Unione e – nella misura in cui ciò possa avere un impatto sull’Unione – nei paesi terzi, comprese informazioni aggiornate sulle cause profonde, sui flussi migratori e dei rifugiati, sulla presenza di minori non accompagnati, sulla capacità complessiva di accoglienza e sulle necessità di reinsediamento dei paesi terzi e su eventuali arrivi massicci di cittadini di paesi terzi che potrebbero sottoporre i sistemi di asilo e di accoglienza degli Stati membri a pressioni sproporzionate.</p>\n<p class=\"oj-normal\">Ai fini di cui al primo comma del presente paragrafo, l’Agenzia lavora in stretta collaborazione con l’Agenzia europea della guardia costiera e di frontiera e, se del caso, tiene conto dell’analisi dei rischi svolta dall’Agenzia europea della guardia costiera e di frontiera a norma nell’articolo 29 del regolamento (UE) 2019/1896, in modo da garantire il massimo livello di coerenza e convergenza delle informazioni fornite dall’Agenzia e dall’Agenzia europea della guardia costiera e di frontiera.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia basa la sua analisi sulle informazioni fornite in particolare dagli Stati membri, dalle istituzioni, dagli organismi, dagli uffici e dalle agenzie dell’Unione competenti, dal Servizio europeo per l’azione esterna (SEAE) e dall’UNHCR, in particolare le relazioni sulle esigenze globali di reinsediamento determinate dall’UNHCR. L’Agenzia può anche tener conto delle informazioni disponibili presso le organizzazioni interessate sulla base delle loro competenze.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia assicura il rapido scambio delle informazioni pertinenti tra gli Stati membri e con la Commissione. Presenta inoltre, in modo tempestivo e accurato, i risultati della sua analisi al consiglio d’amministrazione. L’Agenzia riferisce al Parlamento europeo due volte all’anno in merito alla sua analisi.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Informazioni sull’attuazione del CEAS", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia organizza, coordina e promuove lo scambio di informazioni fra gli Stati membri e fra la questi e la Commissione relativamente all’attuazione del diritto dell’Unione in materia di asilo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia crea banche dati e portali web sugli strumenti relativi all’asilo a livello nazionale, dell’Unione e internazionale, utilizzando, in particolare, i dispositivi esistenti. In tali banche dati o portali web non vengono memorizzati o pubblicati dati personali, a meno che l’Agenzia non li abbia tratti da fonti accessibili al pubblico.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le banche dati e i portali web di cui al paragrafo 2 dispongono di parti accessibili al pubblico che contengono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">statistiche relative al trattamento delle domande di protezione internazionale e relative alle decisioni adottate dalle autorità nazionali competenti in materia di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni sul diritto e gli sviluppi giuridici nazionali in materia di asilo, compresa la giurisprudenza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni sulla giurisprudenza rilevante della Corte di giustizia dell’Unione europea (CGEU) e della Corte europea dei diritti dell’uomo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Funzionari di collegamento negli Stati membri", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo nomina esperti appartenenti al personale dell’Agenzia da impiegare quali funzionari di collegamento negli Stati membri.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In consultazione con gli Stati membri interessati, il direttore esecutivo formula una proposta sulla natura e le condizioni dell’impiego e sullo Stato membro o la regione presso i quali può essere impiegato il funzionario di collegamento. Il direttore esecutivo può stabilire che un funzionario di collegamento si occupi di massimo quattro Stati membri geograficamente limitrofi. La proposta del direttore esecutivo è soggetta ad approvazione del consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo comunica la nomina dei funzionari di collegamento allo Stato membro interessato e stabilisce, insieme a detto Stato membro, la sede dell’impiego.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I funzionari di collegamento agiscono a nome dell’Agenzia e promuovono la cooperazione e il dialogo tra l’Agenzia e le autorità nazionali responsabili per l’asilo e l’immigrazione e altri servizi competenti. In particolare, i funzionari di collegamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fungono da interfaccia tra l’Agenzia e le autorità nazionali responsabili per l’asilo e l’immigrazione e altri servizi competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">favoriscono la raccolta delle informazioni di cui all’articolo 5 e di eventuali altre informazioni richieste dall’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono a promuovere l’applicazione della legislazione dell’Unione in materia di asilo, anche per quanto riguarda il rispetto dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ove richiesto, assistono gli Stati membri nella preparazione dei loro piani di emergenza per far fronte a eventuali pressioni sproporzionate sui loro sistemi di asilo e di accoglienza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitano la comunicazione tra gli Stati membri e tra lo Stato membro interessato e l’Agenzia, e condividono le informazioni pertinenti in possesso dell’Agenzia con lo Stato membro interessato, comprese le informazioni sull’assistenza in corso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono regolarmente relazioni al direttore esecutivo in merito alla situazione dell’asilo nello Stato membro interessato e alla sua capacità di gestire efficacemente i propri sistemi di asilo e di accoglienza.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Qualora nelle relazioni di cui alla lettera f) del primo comma siano sollevate preoccupazioni riguardo a uno o più dei suddetti aspetti d’interesse per lo Stato membro in questione, il direttore esecutivo informa senza indugio tale Stato membro. Tali relazioni sono prese in considerazione ai fini del meccanismo di monitoraggio di cui all’articolo 14 e sono trasmesse allo Stato membro interessato.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Ai fini del paragrafo 4, i funzionari di collegamento mantengono contatti regolari con le autorità nazionali responsabili per l’asilo e l’immigrazione e con altri servizi competenti, mantenendo informato un punto di contatto designato dallo Stato membro interessato.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nell’assolvere ai loro compiti, i funzionari di collegamento ricevono istruzioni soltanto dall’Agenzia.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Formazione", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia organizza, sviluppa e riesamina attività di formazione destinate al proprio personale e al personale delle amministrazioni e degli organismi giurisdizionali nazionali competenti, e alle autorità nazionali responsabili in materia di asilo e di accoglienza.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia organizza le attività di formazione di cui al paragrafo 1 in stretta cooperazione con gli Stati membri e, se opportuno, con l’Agenzia europea della guardia costiera e di frontiera, l’Agenzia dell’Unione europea per i diritti fondamentali, istituita dal regolamento (CE) n. 168/2007 del Consiglio (<span class=\"oj-super oj-note-tag\">19</span>), i competenti organismi di formazione, le istituzioni accademiche, le associazioni di magistrati, le reti di formazione e le organizzazioni pertinenti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia elabora un programma europeo in materia d’asilo tenuto conto della cooperazione esistente all’interno dell’Unione nel settore dell’asilo per promuovere le migliori pratiche e standard elevati nell’applicazione della normativa dell’Unione in materia di asilo.</p>\n<p class=\"oj-normal\">Gli Stati membri elaborano attività di formazione adeguate per il personale conformemente ai loro obblighi in virtù della legislazione dell’Unione in materia di asilo, basandosi sul programma europeo in materia di asilo, e integrano nella formazione parti essenziali di tale programma.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le azioni di formazione offerte dall’Agenzia sono di alta qualità e definiscono principi chiave e migliori prassi al fine di garantire una maggiore convergenza delle prassi e delle decisioni amministrative e delle prassi giuridiche, nel pieno rispetto dell’indipendenza degli organi giudiziari nazionali.</p>\n<p class=\"oj-normal\">Nell’ambito del programma europeo in materia di asilo, la formazione offerta dall’Agenzia riguarda, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le norme internazionali e dell’Unione sui diritti fondamentali, e in particolare le disposizioni della Carta dei diritti fondamentali dell’Unione europea (la «Carta»), così come il diritto internazionale e dell’Unione in materia d’asilo, comprese specifiche questioni giuridiche e giurisprudenziali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti alla determinazione del diritto alla protezione internazionale e dei diritti dei beneficiari della protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti al trattamento delle domande di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le tecniche di intervista;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la valutazione degli elementi di prova;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la giurisprudenza pertinente dei tribunali nazionali, della CGUE, della Corte europea dei diritti dell’uomo e altri pertinenti sviluppi nell’ambito del diritto in materia di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti ai dati dattiloscopici, compresi gli aspetti di protezione dei dati, di qualità dei dati e i requisiti di sicurezza dei dati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’utilizzo delle perizie mediche e legali nelle procedure di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti alla produzione e all’utilizzo delle informazioni sui paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le condizioni di accoglienza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti ai minori, in particolare i minori non accompagnati, per quanto riguarda la valutazione dell’interesse superiore del minore, le garanzie procedurali specifiche come il rispetto del diritto del minore di essere sentito e altri aspetti inerenti alla tutela dei minori, le tecniche di accertamento dell’età e le condizioni di accoglienza per minori e famiglie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti ai richiedenti che necessitano di garanzie procedurali speciali, ai richiedenti con esigenze di accoglienza particolari e altre persone in situazione vulnerabile, con particolare attenzione alle vittime di tortura e alle vittime della tratta di esseri umani e alle questioni relative alla dimensione di genere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti all’interpretazione e alla mediazione culturale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti al reinsediamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti alla gestione delle procedure di ricollocazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le capacità di resilienza e gestione dello stress, in particolare per il personale con mansioni direttive.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia fornisce una formazione generica, specifica o tematica nonché attività di formazione ad hoc, anche utilizzando la metodologia «formazione dei formatori» e l’e-learning.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’Agenzia prende le iniziative necessarie per verificare e, ove opportuno, assicurare che gli esperti, inclusi gli esperti non alle sue dipendenze, appartenenti alle squadre di sostegno per l’asilo abbiano ricevuto la formazione attinente ai loro compiti e alle loro funzioni necessaria per la loro partecipazione alle attività operative organizzate dall’Agenzia.</p>\n<p class=\"oj-normal\">Ove necessario e in anticipo o al momento dell’invio, l’Agenzia fornisce agli esperti di cui al primo comma una formazione specifica per l’assistenza operativa e tecnica fornita nello Stato membro interessato («Stato membro ospitante»).</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L’Agenzia può organizzare attività di formazione sul territorio di uno Stato membro o di un paese terzo in cooperazione con tale Stato membro o paese terzo.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Informazioni sui paesi terzi a livello dell’Unione", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia è un centro di raccolta di informazioni pertinenti, affidabili, obiettive, accurate e aggiornate sui paesi terzi interessati in maniera trasparente e imparziale, che utilizza informazioni pertinenti, incluse le informazioni specifiche relative ai minori e alla dimensione di genere, e le informazioni mirate sulle persone appartenenti a gruppi vulnerabili e minoranze. L’Agenzia redige e aggiorna regolarmente relazioni e altri documenti che forniscono informazioni sui paesi terzi interessati a livello dell’Unione, anche su questioni tematiche specifiche di tali paesi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si avvale di ogni fonte pertinente, comprese le informazioni raccolte da organizzazioni internazionali, in particolare l’UNHCR e altre organizzazioni pertinenti, compresi i membri del forum consultivo di cui all’articolo 50, dalle istituzioni, dagli organismi, dagli uffici e dalle agenzie dell’Unione e dal SEAE, e attraverso le reti di cui all’articolo 10 e le missioni conoscitive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">crea e sviluppa un portale web che raccolga e diffonda le informazioni sui paesi terzi interessati, comprendente una sezione pubblica per gli utenti generici e una sezione ad accesso limitato destinata agli utenti che sono dipendenti delle autorità nazionali responsabili per l’asilo e l’immigrazione o di qualsiasi altro organismo incaricato da uno Stato membro di svolgere attività di ricerca sulle informazioni relative a un paese terzo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elabora un formato e una metodologia comune, compresi i termini di riferimento, in conformità degli obblighi previsti dal diritto dell’Unione in materia d’asilo, per l’elaborazione di relazioni e altri documenti con informazioni sui paesi terzi interessati a livello dell’Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Reti europee per le informazioni sui paesi terzi", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia provvede al coordinamento delle iniziative nazionali di predisposizione di informazioni sui paesi terzi creando e gestendo fra gli Stati membri reti per le informazioni su tali paesi. Tali reti possono, se del caso e su base puntuale, coinvolgere esperti esterni con competenze pertinenti provenienti dall’UNHCR o da altre organizzazioni interessate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le reti di cui al paragrafo 1 servono agli Stati membri, in particolare, per:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambiarsi e aggiornare le relazioni nazionali, altri documenti e altre informazioni pertinenti sui paesi terzi, anche su questioni tematiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presentare all’Agenzia richieste e assisterla nel rispondere a richieste attinenti a specifiche questioni di fatto che potrebbero emergere dalle domande di protezione internazionale, ferme restando le norme sulla tutela della vita privata, le norme sulla protezione dei dati e le norme di riservatezza stabilite dal diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuire all’elaborazione e all’aggiornamento di documenti a livello dell’Unione che forniscano informazioni sui paesi terzi interessati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Analisi comune sulla situazione nei paesi d’origine e note di orientamento", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per promuovere la convergenza nell’applicazione dei criteri di valutazione stabiliti nella direttiva 2011/95/UE del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">20</span>), l’Agenzia coordina gli sforzi fra gli Stati membri per sviluppare un’analisi comune sulla situazione negli specifici paesi d’origine («analisi comune») e note di orientamento che assistano gli Stati membri nella valutazione delle pertinenti domande di protezione internazionale.</p>\n<p class=\"oj-normal\">Nell’elaborazione dell’analisi comune e delle note di orientamento, l’Agenzia tiene conto dei più recenti orientamenti sull’idoneità dell’UNHCR per la valutazione del bisogno di protezione internazionale da parte dei richiedenti asilo provenienti da paesi d’origine specifici.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo, previa consultazione della Commissione, sottopone le note di orientamento al consiglio d’amministrazione per approvazione. Le note di orientamento sono accompagnate dall’analisi comune.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri tengono conto dell’analisi comune e delle note di orientamento nell’esaminare le domande di protezione internazionale, ferma restando la loro competenza a decidere in merito alle singole domande di protezione internazionale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia provvede a che l’analisi comune e le note di orientamento siano oggetto di revisioni regolari e aggiornamenti in base alle necessità. Tali revisioni e aggiornamenti sono effettuati nei casi in cui si verifichino cambiamenti nella situazione in un paese d’origine o vi siano indicazioni oggettive del fatto che l’analisi comune e le note di orientamento non sono utilizzate. Ogni revisione o aggiornamento dell’analisi comune e delle note di orientamento richiede la consultazione preliminare della Commissione e l’approvazione da parte del consiglio d’amministrazione come indicato al paragrafo 2.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri presentano all’Agenzia tutte le informazioni rilevanti che indichino la necessità di una revisione o di un aggiornamento dell’analisi comune e delle note di orientamento.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Informazioni e analisi sui paesi d’origine sicuri e i paesi terzi sicuri", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia può assistere gli Stati membri nell’applicazione dei concetti di paese sicuro conformemente alla direttiva 2013/32/UE del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">21</span>) fornendo informazioni e analisi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia assiste la Commissione nell’ambito dei suoi compiti relativi ai concetti di paese sicuro conformemente alla direttiva 2013/32/UE fornendo informazioni e analisi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel fornire informazioni e analisi fornite a norma dei paragrafi 1 e 2 del presente articolo, l’Agenzia si conforma ai principi generali di cui all’articolo 9.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia sottopone, regolarmente e su richiesta, al Parlamento europeo e al Consiglio le informazioni e le analisi fornite a norma dei paragrafi 1 e 2.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Norme operative, indicatori, orientamenti e migliori prassi", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia organizza e coordina attività volte a promuovere una corretta ed effettiva attuazione del diritto dell’Unione in materia di asilo, anche attraverso l’elaborazione di norme operative, indicatori, orientamenti e migliori prassi su materie attinenti all’asilo, e lo scambio di tali migliori prassi fra gli Stati membri.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia, di propria iniziativa o su richiesta del consiglio di amministrazione o della Commissione, elabora norme operative, indicatori, come pure orientamenti e migliori prassi sull’attuazione del diritto dell’Unione relativi all’asilo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell’elaborazione delle norme operative, degli indicatori, degli orientamenti e delle migliori prassi di cui al paragrafo 2, l’Agenzia consulta la Commissione, gli Stati membri e, se del caso, l’UNHCR. L’Agenzia può inoltre consultare, sulla base delle pertinenti competenze, organizzazioni intergovernative o di altro tipo, come anche associazioni giudiziarie e reti di esperti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d’amministrazione adotta le norme operative, gli indicatori, gli orientamenti e le migliori prassi di cui al paragrafo 2. Dopo la loro adozione, l’Agenzia comunica tali norme operative, indicatori, orientamenti e migliori prassi agli Stati membri e alla Commissione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia assiste gli Stati membri, su loro richiesta, nell’applicare ai propri sistemi di asilo e di accoglienza le norme operative, gli indicatori, gli orientamenti e le migliori prassi di cui al paragrafo 2, fornendo loro le necessarie competenze o assistenza operativa e tecnica.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’Agenzia tiene conto delle norme operative, degli indicatori, degli orientamenti e delle migliori prassi di cui al paragrafo 2 del presente articolo ai fini del meccanismo di monitoraggio di cui all’articolo 14.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Meccanismo di monitoraggio dell’applicazione operativa e tecnica del CEAS", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia, in stretta cooperazione con la Commissione, istituisce un meccanismo di monitoraggio al fine di monitorare l’applicazione operativa e tecnica del CEAS allo scopo di prevenire o di individuare eventuali carenze dei sistemi di asilo e accoglienza degli Stati membri e di valutarne la capacità e la preparazione a gestire situazioni di pressione sproporzionata, al fine di rafforzare l’efficacia di tali sistemi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione, su proposta del direttore esecutivo e in consultazione con la Commissione, definisce una metodologia comune per il meccanismo di monitoraggio di cui al presente capo. La metodologia comune comprende i criteri oggettivi in base ai quali deve essere effettuato il monitoraggio e una descrizione dei metodi, dei processi e degli strumenti per il meccanismo di monitoraggio, quali l’organizzazione pratica delle visite in loco, comprese le visite con breve preavviso, e le norme e i principi per la costituzione delle squadre di esperti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il monitoraggio riguarda l’applicazione operativa e tecnica di tutti gli aspetti del CEAS, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il meccanismo di determinazione dello Stato membro competente per l’esame delle domande di protezione internazionale istituito dal regolamento (UE) n. 604/2013, le procedure relative alla protezione internazionale, l’applicazione dei criteri di valutazione delle esigenze di protezione e la natura della tutela offerta, tenendo conto anche del rispetto dei diritti fondamentali, delle garanzie di protezione dei minori e delle esigenze particolari delle persone in situazioni vulnerabili;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la disponibilità e le capacità del personale in termini di traduzione e interpretazione e le capacità del personale di trattare e gestire efficacemente e correttamente i casi di asilo, compresa la gestione dei ricorsi, fatta salva l’indipendenza giudiziaria e nel pieno rispetto dell’organizzazione del sistema giudiziario di ciascuno Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in relazione all’accoglienza: le condizioni, la capacità, le infrastrutture e le attrezzature e, nella misura del possibile, le risorse finanziarie.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il monitoraggio può essere effettuato, in particolare, sulla base delle informazioni fornite dallo Stato membro interessato, dell’analisi delle informazioni sulla situazione dell’asilo di cui all’articolo 5 e di campionamenti di casi.</p>\n<p class=\"oj-normal\">L’Agenzia può tenere conto delle informazioni fornite da organizzazioni od organismi intergovernativi pertinenti, in particolare l’UNHCR, e da altre organizzazioni pertinenti sulla base delle loro competenze.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia può effettuare visite in loco ai fini del monitoraggio. L’Agenzia effettua le visite con breve preavviso unicamente per le finalità di cui all’articolo 15, paragrafo 2.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri comunicano all’Agenzia, su domanda di questa, le informazioni riguardanti gli aspetti del CEAS di cui al paragrafo 3.</p>\n<p class=\"oj-normal\">Gli Stati membri comunicano all’Agenzia, su domanda di questa, le informazioni riguardanti i loro piani d’emergenza con le misure da prendere per far fronte a eventuali pressioni sproporzionate sul loro sistema di asilo o di accoglienza. L’Agenzia, con l’accordo dello Stato membro interessato, assiste gli Stati membri nella preparazione e nella revisione di tali piani.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Gli Stati membri cooperano con l’Agenzia, anche facilitando ogni eventuale visita in loco da essa svolta ai fini del monitoraggio. Il direttore esecutivo informa gli Stati membri interessati di tali eventuali visite con un preavviso sufficiente. Nel caso delle visite con breve preavviso, il direttore esecutivo informa lo Stato membro interessato con un preavviso di 72 ore.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Procedura e seguiti", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione, sulla base di una proposta del direttore esecutivo e in consultazione con la Commissione, adotta un programma ai fini del meccanismo di monitoraggio di cui all’articolo 14 («programma di monitoraggio») che comprende:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’applicazione operativa e tecnica di tutti gli aspetti del CEAS in ciascuno Stato membro; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli aspetti tematici o specifici del CEAS con riferimento a tutti gli Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il programma di monitoraggio indica gli Stati membri i cui sistemi di asilo e di accoglienza devono essere monitorati in un determinato anno. Il programma di monitoraggio garantisce che ogni Stato membro sia controllato almeno una volta per ogni periodo di cinque anni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogniqualvolta l’analisi delle informazioni sulla situazione dell’asilo di cui all’articolo 5 sollevi serie preoccupazioni riguardanti il funzionamento dei sistemi di asilo o di accoglienza di uno Stato membro, l’Agenzia, di propria iniziativa – in consultazione con la Commissione – o su richiesta di quest’ultima, inizia un monitoraggio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo trasmette le risultanze di un monitoraggio allo Stato membro interessato affinché formuli le proprie osservazioni, anche indicando, se del caso, le proprie esigenze. Gli Stati membri hanno un termine di un mese dalla data di ricezione delle risultanze per presentare osservazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, sulla base delle risultanze di cui al paragrafo 3 e tenendo conto delle osservazioni dello Stato membro interessato, nonché in consultazione con la Commissione, elabora delle bozze di raccomandazioni. Tali bozze di raccomandazioni delineano le misure che lo Stato membro interessato dovrà adottare, anche con l’aiuto dell’Agenzia, se necessario, e un termine entro il quale le eventuali misure necessarie dovranno essere adottate dallo Stato membro interessato per affrontare le carenze o i problemi relativi alle capacità e alla preparazione individuati nel monitoraggio. Il direttore esecutivo inoltra le bozze di raccomandazioni allo Stato membro interessato. Lo Stato membro interessato dispone di un mese dalla data di ricezione della bozza di raccomandazione per inviare le proprie osservazioni in merito. Nei casi di cui al paragrafo 2, lo Stato membro interessato presenta le proprie osservazioni entro 15 giorni.</p>\n<p class=\"oj-normal\">Dopo aver tenuto conto delle osservazioni dello Stato membro interessato, il direttore esecutivo sottopone le risultanze e le bozze di raccomandazioni al consiglio d’amministrazione. Il consiglio d’amministrazione, deliberando a maggioranza di due terzi dei suoi membri aventi diritto di voto, adotta le raccomandazioni. L’Agenzia trasmette le raccomandazioni al Parlamento europeo. L’Agenzia informa la Commissione in merito all’attuazione delle raccomandazioni.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Se uno Stato membro non attua le misure delineate nelle raccomandazioni elaborate dall’Agenzia di cui al paragrafo 4 entro il termine fissato, con gravi conseguenze per il funzionamento del CEAS, la Commissione, in base alla propria valutazione, adotta delle raccomandazioni indirizzate a tale Stato membro in cui identifica le misure necessarie per rimediare alle carenze e, ove necessario, indica i provvedimenti specifici che l’Agenzia deve prendere per sostenere tale Stato membro.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Tenuto conto della gravità delle carenze, la Commissione può organizzare visite in loco nello Stato membro interessato. La Commissione informa gli Stati membri interessati di tali eventuali visite con un preavviso sufficiente.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Lo Stato membro interessato riferisce alla Commissione in merito all’attuazione delle raccomandazioni di cui al paragrafo 5 del presente articolo entro il termine fissato nelle raccomandazioni stesse. Se, trascorso tale termine, lo Stato membro interessato non ha pienamente adempiuto alle raccomandazioni, la Commissione può presentare una proposta di atto di esecuzione del Consiglio conformemente all’articolo 22, paragrafo 1.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   La Commissione informa il Parlamento europeo e il Consiglio in merito ad ogni eventuale seguito dato al monitoraggio. La Commissione trasmette al Parlamento europeo e al Consiglio le raccomandazioni di cui al paragrafo 5 e li informa periodicamente in merito ai progressi compiuti dallo Stato membro interessato nell’attuazione di tali raccomandazioni.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Assistenza operativa e tecnica prestata dall’Agenzia", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia fornisce assistenza operativa e tecnica a uno Stato membro conformemente al presente capo:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">su richiesta dello Stato membro per quanto riguarda l’attuazione dei suoi obblighi nell’ambito del CEAS;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">su richiesta dello Stato membro, qualora i suoi sistemi di asilo o di accoglienza siano sottoposti a pressioni sproporzionate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">qualora lo Stato membro si trovi a far fronte a sfide migratorie sproporzionate e richieda un rafforzamento operativo e tecnico mediante l’invio di squadre di sostegno alla gestione della migrazione a norma dell’articolo 21;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">su propria iniziativa e con l’accordo dello Stato membro, qualora il sistema di asilo o di accoglienza dello Stato membro sia sottoposto a pressioni sproporzionate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando fornisce assistenza operativa e tecnica a norma dell’articolo 22.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia organizza e coordina l’opportuna assistenza operativa e tecnica, che può comportare l’adozione di una o più delle seguenti misure operative e tecniche rispettando pienamente i diritti fondamentali:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza agli Stati membri nell’identificazione e nella registrazione dei cittadini dei paesi terzi, se del caso, in stretta collaborazione con altri organismi, uffici e agenzie dell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza agli Stati membri nella ricezione e nella registrazione delle domande di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">agevolazione dell’esame da parte delle autorità nazionali competenti delle domande di protezione internazionale o prestazione a tali autorità della necessaria assistenza nella procedura di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">agevolazione delle iniziative congiunte fra Stati membri per il trattamento delle domande di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza nella comunicazione di informazioni sulla procedura di protezione internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">consulenza, assistenza o coordinamento nella creazione o nella messa a disposizione di strutture di accoglienza da parte degli Stati membri, in particolare di alloggi d’emergenza, mezzi di trasporto e assistenza medica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prestazione di sostegno adeguato agli Stati membri nell’assolvimento dei loro compiti e dei loro obblighi a norma del regolamento (UE) n. 604/2013;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza nella ricollocazione o nel trasferimento di richiedenti o di beneficiari di protezione internazionale nell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prestazione di servizi di interpretariato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza agli Stati membri affinché possano assicurare tutte le necessarie garanzie relative ai diritti e alla tutela dei minori, con particolare riferimento ai minori non accompagnati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza agli Stati membri nell’individuare i richiedenti che necessitano di particolari garanzie procedurali o che hanno particolari esigenze di accoglienza, o altre persone in situazione vulnerabile, compresi i minori, nell’indirizzare tali persone alle autorità nazionali competenti affinché ricevano l’assistenza adeguata sulla base di misure nazionali e nell’assicurare che siano predisposte tutte le garanzie necessarie a favore di tali persone;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">partecipazione alle squadre di sostegno per la gestione della migrazione nei punti di crisi (hotspot) di cui al regolamento (UE) 2019/1896, in stretta collaborazione con altri organismi, uffici o agenzie dell’Unione competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">invio di squadre di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">predisposizione di attrezzature tecniche per le squadre di sostegno per l’asilo, se del caso.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia finanzia o cofinanzia le misure operative e tecniche di cui al paragrafo 2 con il proprio bilancio, conformemente alla normativa finanziaria ad essa applicabile.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo valuta i risultati delle misure operative e tecniche di cui al paragrafo 2 del presente articolo. Entro 60 giorni dall’adozione di tali misure, il direttore esecutivo trasmette al consiglio d’amministrazione relazioni di valutazione dettagliate, unitamente alle osservazioni del responsabile dei diritti fondamentali, conformemente al programma di rendiconto e valutazione previsto dal piano operativo di cui all’articolo 18, paragrafo 2, lettera k). L’Agenzia effettua un’analisi comparativa globale di tali risultati, e la include nella relazione annuale sulla situazione dell’asilo di cui all’articolo 69.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Procedura per la prestazione di assistenza operativa e tecnica", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri trasmettono le richieste di assistenza a norma dell’articolo 16, paragrafo 1, lettera a), b) o c), al direttore esecutivo. Tali richieste descrivono la situazione, precisando lo scopo della richiesta, e sono corredate di una valutazione dettagliata delle necessità e, se del caso, di una descrizione delle misure già adottate a livello nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora uno Stato membro accetti l’assistenza proposta su iniziativa dell’Agenzia a norma dell’articolo 16, paragrafo 1, lettera d), lo Stato membro interessato presenta all’Agenzia una valutazione dettagliata delle necessità e, se del caso, una descrizione delle misure già adottate a livello nazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo valuta, approva e coordina le richieste di assistenza, compreso l’invio delle squadre di sostegno per l’asilo. Il direttore esecutivo notifica immediatamente al consiglio di amministrazione la ricezione di una richiesta di assistenza a norma dell’articolo 16, paragrafo 1, lettera a), b) o c), o una proposta dell’Agenzia di fornire assistenza di propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d). Il direttore esecutivo esamina la valutazione dettagliata delle necessità presentata dallo Stato membro interessato a norma del paragrafo 1 o 2 del presente articolo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia sottopone ciascuna richiesta di assistenza a norma dell’articolo 16, paragrafo 1, lettera a), b) o c), e la proposta di fornire assistenza di propria iniziativa a norme dell’articolo 16, paragrafo 1, lettera d), a un esame approfondito e accurato che consente all’Agenzia di individuare e proporre una o più delle misure, di cui all’articolo 16, paragrafo 2, al fine di soddisfare le necessità dello Stato membro interessato. Ove necessario, il direttore esecutivo può inviare esperti dell’Agenzia per valutare la situazione dello Stato membro bisognoso di assistenza.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo decide in merito alla prestazione di assistenza operativa e tecnica, compreso l’invio di squadre di sostegno per l’asilo:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro tre giorni lavorativi dalla data di ricevimento di una richiesta a norma dell’articolo 16, paragrafo 1, lettera a), b) o c); o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro tre giorni lavorativi dalla data in cui lo Stato membro interessato fornisce il proprio accordo a una proposta dell’Agenzia di fornire assistenza di propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d).</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Laddove il direttore esecutivo invia degli esperti allo Stato membro interessato a norma del paragrafo 4, il direttore esecutivo decide come indicato nel primo comma entro cinque giorni lavorativi dalla data di cui al punto a) o b, a seconda dei casi.</p>\n<p class=\"oj-normal\">Al momento di adottare la decisione di cui al primo comma, il direttore esecutivo comunica per iscritto allo Stato membro interessato e al consiglio di amministrazione la decisione, precisando le motivazioni principali su cui detta decisione si basa.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Piano operativo", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Laddove si debba fornire assistenza operativa e tecnica, il direttore esecutivo elabora un piano operativo in cooperazione con lo Stato membro ospitante. Il direttore esecutivo e lo Stato membro ospitante concordano il piano operativo:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro dieci giorni lavorativi dalla data in cui è stata presa una decisione di cui all’articolo 17, paragrafo 5, nel caso di una richiesta di assistenza a norma dell’articolo 16, paragrafo 1, lettera a),</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro cinque giorni lavorativi dalla data in cui è stata presa una decisione di cui all’articolo 17, paragrafo 5, nel caso di una richiesta di assistenza a norma dell’articolo 16, paragrafo 1, lettera b), o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro cinque giorni lavorativi dalla data in cui lo Stato membro fornisce il proprio accordo a una proposta dell’Agenzia di fornire assistenza su propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d).</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">L’Agenzia consulta gli Stati membri partecipanti, ove necessario, in merito al piano operativo tramite i referenti nazionali di cui all’articolo 24.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Un piano operativo è vincolante per l’Agenzia, per lo Stato membro ospitante e per gli Stati membri partecipanti. Esso descrive in dettaglio le condizioni dell’invio delle squadre di sostegno per l’asilo nel quadro dell’assistenza operativa e tecnica da fornire, come pure gli aspetti organizzativi, fra cui i seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione della situazione e il modus operandi e gli obiettivi dell’invio delle squadre di sostegno per l’asilo, scopo operativo compreso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la durata prevedibile della missione delle squadre di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il luogo dello Stato membro ospitante in cui sono inviate le squadre di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">aspetti logistici, fra cui informazioni sulle condizioni di lavoro per le squadre di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione chiara e dettagliata dei compiti e delle responsabilità delle squadre di sostegno per l’asilo, anche per quanto riguarda i diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istruzioni specifiche per le squadre di sostegno per l’asilo, anche per quanto concerne le banche dati nazionali ed europee che sono autorizzati a consultare e l’equipaggiamento che possono usare o portare nello Stato membro ospitante;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la composizione delle squadre di sostegno per l’asilo in termini di profilo e numero degli esperti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le attrezzature tecniche, con specifiche disposizioni come le condizioni d’uso, il trasporto e altri aspetti logistici, e le disposizioni finanziarie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">attività di sviluppo delle capacità connesse all’assistenza operativa e tecnica fornita;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per quanto riguarda l’assistenza nell’ambito delle domande di protezione internazionale, incluso l’esame di tali domande, e fatta salva la competenza degli Stati membri a decidere in merito alle singole domande di protezione internazionale, informazioni specifiche sui compiti che le squadre di sostegno per l’asilo possono svolgere e una chiara descrizione delle loro responsabilità e della normativa applicabile dell’Unione, nazionale e internazionale, incluso il regime di responsabilità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un programma di rendiconto e valutazione contenente i parametri per una relazione di valutazione e il termine per presentare la relazione di valutazione finale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se del caso, le condizioni di cooperazione con i paesi terzi, gli organismi, gli uffici e le agenzie dell’Unione o con le organizzazioni internazionali nell’ambito dei rispettivi mandati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le misure atte a indirizzare le persone che necessitano di protezione internazionale, le vittime della tratta di esseri umani, i minori e qualsiasi altra persona in situazione vulnerabile verso le autorità nazionali competenti per ricevere l’assistenza adeguata;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le modalità pratiche relative al meccanismo di denuncia di cui all’articolo 51.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Negli Stati membri in cui l’UNHCR opera e ha la capacità di contribuire a rispondere a una richiesta di assistenza operativa e tecnica a norma dell’articolo 16, paragrafo 1, l’Agenzia si coordina con l’UNHCR per quanto riguarda l’attuazione del piano operativo, ove opportuno e con l’accordo dello Stato membro interessato.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   In relazione al paragrafo 2, lettera f), lo Stato membro ospitante autorizza gli esperti che partecipano alle squadre di sostegno per l’asilo a consultare le banche dati europee, e può autorizzarli a consultare le proprie banche dati nazionali conformemente alla pertinente normativa europea e nazionale relativa all’accesso e alla consultazione di tali banche dati, nella misura in cui ciò è necessario per conseguire gli obiettivi e svolgere i compiti indicati nel piano operativo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Eventuali modifiche o adattamenti di un piano operativo sono subordinati al consenso del direttore esecutivo e dello Stato membro ospitante, previa consultazione degli Stati membri partecipanti, se del caso. L’Agenzia trasmette immediatamente copia del piano operativo modificato o adattato ai referenti nazionali degli Stati membri partecipanti di cui all’articolo 24.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo, dopo avere informato lo Stato membro ospitante, sospende o conclude, totalmente o in parte, l’invio di squadre di sostegno per l’asilo qualora:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le condizioni per l’esecuzione delle misure operative e tecniche di cui all’articolo 16, paragrafo 2, non ricorrano più,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo Stato membro ospitante non rispetti il piano operativo,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dopo aver consultato il responsabile dei diritti fondamentali, il direttore esecutivo ritenga che si sia in presenza di violazioni dei diritti fondamentali o degli obblighi di protezione internazionale da parte dello Stato membro che sono di natura grave o possono persistere.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Composizione delle squadre di sostegno per l’asilo", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore operativo stabilisce la composizione di ciascuna squadra di sostegno per l’asilo. Le squadre di sostegno per l’asilo sono composte da:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esperti appartenenti al personale dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esperti degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esperti distaccati dagli Stati membri all’Agenzia; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altri esperti non impiegati dall’Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Al momento di determinare la composizione di una squadra di sostegno per l’asilo, il direttore esecutivo tiene conto delle circostanze particolari in cui versa lo Stato membro interessato. Una squadra di sostegno per l’asilo è costituita secondo il piano operativo pertinente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su proposta del direttore esecutivo il consiglio d’amministrazione decide in merito ai profili e al numero complessivo degli esperti da mettere a disposizione di una squadra di sostegno per l’asilo. La stessa procedura si applica a eventuali successive modifiche dei profili e del numero complessivo di esperti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri contribuiscono alle squadre di sostegno per l’asilo nominando esperti nazionali corrispondenti ai profili richiesti, quali stabiliti dal consiglio d’amministrazione a norma del paragrafo 2. Il numero degli esperti che ciascuno Stato membro dovrà mettere a disposizione per l’anno successivo è definito sulla base di negoziati e accordi bilaterali annuali tra l’Agenzia e lo Stato membro interessato.</p>\n<p class=\"oj-normal\">Conformemente agli accordi di cui al primo comma, gli Stati membri tengono a disposizione i propri esperti o gli esperti che hanno distaccato presso l’Agenzia su richiesta di quest’ultima. Tuttavia, qualora uno Stato membro si trovi a far fronte a una situazione eccezionale che incide in misura sostanziale sull’adempimento dei compiti nazionali, non è tenuto a mettere a disposizione tali esperti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia contribuisce alle squadre di sostegno per l’asilo con esperti del proprio personale, compresi esperti impiegati e formati per il lavoro sul campo e interpreti con almeno una formazione di base o una comprovata esperienza, che possono essere assunti negli Stati membri ospitanti, o con esperti non impiegati dall’Agenzia, con comprovate e pertinenti conoscenze ed esperienza in conformità delle esigenze operative.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nell’ambito delle squadre di sostegno per l’asilo, l’Agenzia stabilisce un elenco di interpreti. Gli Stati membri assistono l’Agenzia nell’individuazione degli interpreti da inserire nell’elenco, incluse persone che non fanno parte dell’amministrazione nazionale degli Stati membri. L’assistenza all’interpretazione può essere fornita mediante l’invio di interpreti nello Stato membro interessato o, se del caso, in videoconferenza.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   È istituito un gruppo di riserva in materia d’asilo comprendente almeno 500 esperti ai fini dell’invio delle squadre di sostegno per l’asilo nel quadro delle richieste di assistenza a norma dell’articolo 16, paragrafo 1, lettera b), delle proposte da parte dell’Agenzia di fornire assistenza su propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d), e dell’assistenza fornita dall’Agenzia a norma dell’articolo 22. Il gruppo di riserva in materia d’asilo costituisce una riserva di esperti immediatamente a disposizione dell’Agenzia. A tal fine, ciascuno Stato membro mette a disposizione del gruppo di riserva in materia d’asilo il numero di esperti indicato all’allegato I. Il consiglio di amministrazione, su proposta del direttore esecutivo, decide a maggioranza dei tre quarti dei membri aventi diritto di voto in merito ai profili degli esperti da includere nel gruppo di riserva in materia d’asilo. La stessa procedura si applica a eventuali successive modifiche dei profili degli esperti.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il direttore esecutivo può verificare se gli esperti messi a disposizione del gruppo di riserva in materia d’asilo dagli Stati membri conformemente al paragrafo 6 corrispondono ai profili stabiliti dal consiglio d’amministrazione a norma di tale paragrafo. Prima dell’invio, il direttore esecutivo può chiedere a uno Stato membro di depennare un esperto dal gruppo di riserva in materia d’asilo in caso l’esperto in questione non corrisponda al profilo richiesto e di sostituirlo con un esperto che corrisponda a uno dei profili richiesti.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Fatto salvo l’articolo 22, paragrafo 5, e di fronte a una situazione eccezionale che incide in misura sostanziale sull’adempimento dei compiti nazionali, comprovata dall’analisi delle informazioni sulla situazione dell’asilo di cui all’articolo 5, uno Stato membro può richiedere per iscritto al consiglio di amministrazione di essere temporaneamente esonerato dall’obbligo di mettere esperti a disposizione del gruppo di riserva in materia d’asilo. Tale richiesta è motivata in modo esauriente e contiene informazioni sulla situazione in cui versa lo Stato membro in questione. Il consiglio di amministrazione decide, a maggioranza dei tre quarti dei suoi membri aventi diritto di voto, se esonerare temporaneamente tale Stato membro da una parte del suo contributo indicato all’allegato I.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Invio delle squadre di sostegno per l’asilo", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia invia negli Stati membri squadre di sostegno per l’asilo per fornire assistenza operativa e tecnica a norma dell’articolo 16, paragrafo 1.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Non appena concordato il piano operativo a norma dell’articolo 18, paragrafo 1, o dell’articolo 22, paragrafo 2, il direttore esecutivo chiede agli Stati membri di inviare i propri esperti entro dieci giorni lavorativi. La richiesta è trasmessa per iscritto, corredata da una copia del piano operativo, ai referenti nazionali di cui all’articolo 24 e menzionano la data di invio prevista.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo invia le squadre di sostegno per l’asilo attingendo al gruppo di riserva in materia d’asilo nel quadro di una richiesta di assistenza a norma dell’articolo 16, paragrafo 1, lettera b), di una proposta dell’Agenzia di fornire assistenza su propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d), o di assistenza fornita dall’Agenzia a norma dell’articolo 22. L’invio di esperti provenienti dal gruppo di riserva in materia d’asilo ha luogo entro sette giorni lavorativi a decorrere dalla data in cui viene concordato il piano operativo conformemente all’articolo 18, paragrafo 1, o all’articolo 22, paragrafo 2.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri mettono a disposizione, senza indebiti ritardi, gli esperti del gruppo di riserva in materia d’asilo come stabilito dal direttore esecutivo. Lo Stato membro ospitante non invia esperti facenti parte del suo contributo fisso al gruppo di riserva in materia d’asilo. Qualora emerga una carenza di esperti da inviare in missione nell’ambito del gruppo di riserva in materia d’asilo, il consiglio di amministrazione, su proposta del direttore esecutivo, decide in che modo ovviare a tale carenza. Il direttore esecutivo informa il Parlamento europeo, il Consiglio e la Commissione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Lo Stato membro da cui viene inviato l’esperto («Stato membro di origine») determina la durata della missione. Essa non è inferiore a 45 giorni, tranne nel caso in cui l’assistenza operativa e tecnica in questione sia richiesta per una durata inferiore.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo può chiedere a uno Stato membro di depennare un esperto da un gruppo di riserva in materia d’asilo in caso di condotta scorretta o di violazione delle norme applicabili alla missione. In tali casi, l’esperto in questione non è preso in considerazione per future missioni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L’Agenzia informa il Parlamento europeo, mediante la sua relazione annuale sulla situazione dell’asilo nell’Unione di cui all’articolo 69, del numero di esperti che gli Stati membri si sono impegnati a mettere a disposizione e del numero di esperti effettivamente inviati presso le squadre di sostegno per l’asilo a norma del presente articolo. Tale relazione elenca gli Stati membri che hanno invocato la situazione eccezionale di cui all’articolo 19, paragrafo 3 o 8, nel corso dell’anno precedente. Essa include altresì le motivazioni alla base di tale richiesta e le informazioni fornite dallo Stato membro interessato.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Squadre di sostegno per la gestione della migrazione", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora uno Stato membro chieda un rinforzo operativo e tecnico da parte delle squadre di sostegno per la gestione della migrazione ai sensi dell’articolo 40 del regolamento (UE) 2019/1896, o qualora vengano inviate squadre di sostegno per la gestione della migrazione nei punti di crisi (hotspot) sulla base dell’articolo 42 del suddetto regolamento, il direttore esecutivo opera in stretta collaborazione con l’Agenzia europea della guardia di frontiera e costiera quando esamina, conformemente all’articolo 40, paragrafo 2, di tale regolamento, in coordinamento con altri organismi, uffici e agenzie competenti dell’Unione, la richiesta di rinforzo presentata da uno Stato membro e la valutazione delle sue esigenze allo scopo di definire un insieme completo di misure di rinforzo, consistenti di varie attività coordinate dagli organismi, dagli uffici e dalle agenzie competenti dell’Unione, che deve essere approvato dallo Stato membro interessato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione, in cooperazione con lo Stato membro ospitante e gli organismi, uffici e agenzie competenti dell’Unione, stabilisce le modalità di cooperazione presso il punto di crisi ed è responsabile del coordinamento fra le attività delle squadre di sostegno per la gestione della migrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei casi di cui al paragrafo 1, il direttore esecutivo avvia la procedura per l’invio delle squadre di sostegno per l’asilo nell’ambito delle squadre di sostegno per la gestione della migrazione, includendo, se del caso, esperti del gruppo di riserva in materia d’asilo. Il rinforzo operativo e tecnico fornito dalle squadre di sostegno per l’asilo nel contesto delle squadre di sostegno per la gestione della migrazione può comprendere:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’assistenza nello screening dei cittadini di paesi terzi, compresa la loro identificazione, registrazione, nonché, se richiesto dallo Stato membro ospitante, il rilevamento delle loro impronte digitali e la comunicazione di informazioni circa la finalità di tali procedure;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la comunicazione di informazioni preliminari ai cittadini di paesi terzi che desiderano richiedere protezione internazionale e l’indirizzamento di tali cittadini di paesi terzi presso le autorità nazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la comunicazione di informazioni ai richiedenti protezione internazionale sulla procedura di protezione internazionale, sulle condizioni di accoglienza a seconda dei casi e sulla ricollocazione, come pure la fornitura della necessaria assistenza per i richiedenti o potenziali richiedenti suscettibili di ricollocazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la registrazione delle domande di protezione internazionale e, se richiesto dallo Stato membro ospitante, l’agevolazione dell’esame di tali domande.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Situazione di pressione sproporzionata sui sistemi di asilo e di accoglienza o inefficacia degli stessi", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il Consiglio, sulla base di una proposta della Commissione a norma dell’articolo 15, paragrafo 7, può adottare senza indugio una decisione mediante atto di esecuzione, in cui indica una o più delle misure di cui all’articolo 16, paragrafo 2, che l’Agenzia deve adottare per sostenere uno Stato membro e che impone a tale Stato membro di cooperare con l’Agenzia nell’attuazione di tali misure, quando il sistema di asilo o di accoglienza di tale Stato membro sia reso inefficaci al punto in cui ciò ha gravi ripercussioni sul funzionamento del CEAS e quando:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il sistema di asilo e di accoglienza di tale Stato membro sia sottoposto a una pressione sproporzionata che implichi, per esso, oneri eccezionalmente pesanti e urgenti e tale Stato membro non intraprende un’azione sufficiente per far fronte a tale pressione, tra cui non richiedere assistenza operativa e tecnica a norma dell’articolo 16, paragrafo 1, lettera a), b) o c), o non aderire a una proposta dell’Agenzia di fornire tale assistenza su propria iniziativa a norma dell’articolo 16, paragrafo 1, lettera d); o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tale Stato membro non si conforma alla raccomandazione della Commissione di cui all’articolo 15, paragrafo 5.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il Consiglio trasmette le decisioni di cui al primo comma al Parlamento europeo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo, entro tre giorni lavorativi dalla data di adozione di una decisione del Consiglio di cui al paragrafo 1, stabilisce i dettagli dell’attuazione pratica di tale decisione del Consiglio. Parallelamente, il direttore esecutivo redige un piano operativo e lo sottopone allo Stato membro interessato. Il direttore esecutivo e lo Stato membro interessato concordano il piano operativo entro tre giorni lavorativi dalla data di presentazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia invia gli esperti necessari del gruppo di riserva in materia d’asilo ed esperti appartenenti al proprio personale, conformemente all’articolo 20, paragrafo 3. L’Agenzia può inviare ulteriori squadre di sostegno per l’asilo, se necessario.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Lo Stato membro interessato si conforma alla decisione del Consiglio di cui al paragrafo 1. A tale scopo coopera con l’Agenzia e intraprende immediatamente le azioni necessarie per agevolare l’attuazione della decisione e l’esecuzione pratica delle misure stabilite nella stessa e nel piano operativo, ferma restando la sua competenza a decidere in merito alle singole domande di protezione internazionale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Ai fini del presente articolo, gli Stati membri mettono a disposizione gli esperti del gruppo di riserva in materia d’asilo come stabilito dal direttore esecutivo e non invocano la situazione eccezionale di cui all’articolo 19, paragrafi 3 o 8. Lo Stato membro ospitante non invia esperti facenti parte del suo contributo fisso al gruppo di riserva in materia d’asilo.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Attrezzature tecniche", "anchor": "art_23", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fermo restando l’obbligo dello Stato membro ospitante di fornire le strutture e le attrezzature necessarie affinché l’Agenzia possa apportare l’assistenza operativa e tecnica richiesta, l’Agenzia può utilizzare le proprie attrezzature nello Stato membro ospitante, anche su sua richiesta, nella misura in cui tali attrezzature possano essere necessarie alle squadre di sostegno per l’asilo e nella misura in cui tali attrezzature possano integrare attrezzature già messe a disposizione dallo Stato membro ospitante o da altre agenzie dell’Unione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia può acquistare o noleggiare attrezzature tecniche su decisione del direttore esecutivo in consultazione con il consiglio d’amministrazione. L’acquisto o il noleggio delle attrezzature tecniche sono preceduti da un’attenta analisi costi-benefici e del fabbisogno. Eventuali spese riconducibili all’acquisto o al noleggio sono iscritte nel bilancio dell’Agenzia e conformemente alle regole finanziarie applicabili all’Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia garantisce la sicurezza delle sue attrezzature durante il loro intero ciclo di vita.</p>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Referente nazionale", "anchor": "art_24", "frags": [[null, "<p class=\"oj-normal\">Ciascuno Stato membro designa un referente nazionale incaricato di comunicare con l’Agenzia in merito a tutte le questioni attinenti all’assistenza operativa e tecnica di cui agli articoli 16 e 22.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Agente di coordinamento dell’Agenzia", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia garantisce l’attuazione operativa di tutti gli aspetti organizzativi, compresi la presenza di membri del suo personale, relativi all’invio delle squadre di sostegno per l’asilo, nel corso dell’intera prestazione dell’assistenza operativa e tecnica a norma dell’articolo 16 o 22.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo nomina uno o più esperti dell’Agenzia che intervengano o che siano inviati in qualità di agenti di coordinamento ai fini del paragrafo 1. Il direttore esecutivo comunica la nomina allo Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’agente di coordinamento favorisce la cooperazione e il coordinamento fra lo Stato membro ospitante e gli Stati membri partecipanti. In particolare, l’agente di coordinamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funge da interfaccia fra l’Agenzia, lo Stato membro ospitante e gli esperti partecipanti alle squadre di sostegno per l’asilo, fornendo assistenza, per conto dell’Agenzia, su tutte le questioni connesse alle condizioni di impiego degli esperti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controlla la corretta attuazione del piano operativo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">agisce a nome dell’Agenzia per tutti gli aspetti relativi all’impiego delle squadre di sostegno per l’asilo e riferisce all’Agenzia su tutti tali aspetti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferisce al direttore esecutivo qualora il piano operativo non venga adeguatamente attuato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo può autorizzare l’agente di coordinamento a contribuire alla soluzione di eventuali disaccordi relativi all’attuazione del piano operativo e all’invio delle squadre di sostegno per l’asilo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nell’assolvimento dei suoi compiti l’agente di coordinamento lavora in stretta cooperazione con le autorità nazionali competenti e riceve istruzioni solo dal direttore esecutivo.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Responsabilità civile", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro ospitante è responsabile dei danni eventuali causati dagli esperti che partecipano a una squadra di sostegno per l’asilo sul suo territorio durante le loro operazioni, conformemente alla sua legislazione nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ove tali danni siano causati da negligenza grave o comportamento doloso da parte di esperti che partecipano a una squadra di sostegno per l’asilo, lo Stato membro ospitante può chiedere allo Stato membro di origine o all’Agenzia il rimborso di eventuali risarcimenti che ha versato alle parti lese o agli aventi diritto a tale risarcimento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l’esercizio dei suoi diritti nei confronti di terzi, ciascuno Stato membro rinuncia a chiedere allo Stato membro ospitante o a qualsiasi altro Stato membro il risarcimento dei danni subiti, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali controversie tra gli Stati membri o uno Stato membro e l’Agenzia sull’applicazione dei paragrafi 2 e 3 che tali Stati non possano risolvere mediante negoziati sono da essi deferite alla CGUE ai sensi dell’articolo 273 TFUE.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatto salvo l’esercizio dei suoi diritti nei confronti di terzi, l’Agenzia sostiene le spese per i danni causati al proprio equipaggiamento durante la missione, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Responsabilità penale", "anchor": "art_27", "frags": [[null, "<p class=\"oj-normal\">Durante la missione di una squadra di sostegno per l’asilo, gli esperti inviati sono assimilati ai funzionari dello Stato membro ospitante per quanto riguarda i reati che potrebbero commettere o di cui potrebbero essere vittime.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Costi", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia sostiene i costi sostenuti dagli esperti che partecipano alle squadre di sostegno per l’asilo, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi relativi al viaggio dallo Stato membro di origine allo Stato membro ospitante, al viaggio dallo Stato membro ospitante allo Stato membro di origine e al viaggio all’interno dello Stato membro ospitante ai fini della missione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di vaccinazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi relativi ad assicurazioni specifiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di assistenza sanitaria;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la diaria, compresi i costi per l’alloggio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costi relativi alle attrezzature tecniche dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli onorari degli esperti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di trasposto, inclusi i costi per il noleggio di autoveicoli e tutte le spese correlate, quali l’assicurazione, il carburante e i pedaggi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di telecomunicazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione stabilisce e aggiorna, ove necessario, le regole specifiche per il pagamento dei costi sostenuti dagli esperti a norma del paragrafo 1.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Sistemi di scambio di informazioni", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia agevola lo scambio con la Commissione e gli Stati membri e, se del caso, con i pertinenti organismi, uffici e agenzie dell’Unione, di informazioni utili all’assolvimento dei suoi compiti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia, in cooperazione con l’Agenzia dell’Unione europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia (eu-LISA), istituita col regolamento (UE) 2018/1726 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">22</span>), sviluppa e gestisce un sistema informativo che permetta di scambiare informazioni classificate conformemente alla decisione 2013/488/UE del Consiglio (<span class=\"oj-super oj-note-tag\">23</span>) e alla decisione (UE, Euratom) 2015/444 della Commissione (<span class=\"oj-super oj-note-tag\">24</span>) e i dati personali di cui agli articoli 31 e 32 del presente regolamento con gli interlocutori di cui al paragrafo 1 del presente articolo.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Protezione dei dati", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il regolamento (UE) 2018/1725 si applica al trattamento dei dati personali da parte dell’Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione adotta misure per l’applicazione del regolamento (UE) 2018/1725 da parte dell’Agenzia, anche in relazione alla nomina del responsabile della protezione dei dati dell’Agenzia. Tali misure sono adottate previa consultazione del garante europeo della protezione dei dati.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatti salvi gli articoli 31 e 32, l’Agenzia può trattare i dati personali per i necessari scopi amministrativi connessi al personale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sono vietate la trasmissione di dati personali trattati dall’Agenzia e la trasmissione ulteriore da parte degli Stati membri dei dati personali trattati nell’ambito del presente regolamento ad autorità di paesi terzi o a terze parti, incluse le organizzazioni internazionali.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   In deroga al paragrafo 4, l’Agenzia può trasmettere, fermo restando il consenso informato e liberamente prestato del cittadino di uno stato terzo, individuato ai soli fini dello svolgimento di una procedura di reinsediamento, il suo nome e cognome, le informazioni sull’avanzamento della procedura di reinsediamento che lo riguardano e le informazioni sull’esito della stessa alle pertinenti organizzazioni internazionali nella misura necessaria per dette finalità. Tali dati personali non sono soggetti a ulteriore trattamento per altri fini o a trasmissione ulteriore.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Quando gli esperti partecipanti alle squadre di sostegno per l’asilo trattano i dati personali seguendo le istruzioni dello Stato membro ospitante e quando viene prestata assistenza operativa e tecnica a tale Stato membro si applica il regolamento (UE) 2016/679.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Finalità del trattamento dei dati personali", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia tratta i dati personali solo nella misura in cui ciò è necessario e per i seguenti scopi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prestazione di assistenza tecnica e operativa a norma dell’articolo 16, paragrafo 2, e dell’articolo 21, paragrafi 2 e 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo svolgimento di campionamenti di casi ai fini del monitoraggio di cui all’articolo 14;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la facilitazione dello scambio di informazioni con le autorità competenti nazionali, con l’Agenzia europea della guardia di frontiera e costiera, con Europol o Eurojust conformemente all’articolo 37, e nel quadro delle informazioni ottenute durante lo svolgimento dei compiti di cui all’articolo 21, paragrafo 3, ove necessario per lo svolgimento dei loro compiti in conformità ai rispettivi mandati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’analisi delle informazioni sulla situazione dell’asilo di cui all’articolo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’assistenza agli Stati membri nelle azioni relative al reinsediamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualsiasi trattamento di dati personali rispetta il principio di proporzionalità ed è strettamente limitato ai dati personali necessari per le finalità di cui al paragrafo 1.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri o altri organismi, uffici e agenzie dell’Unione che forniscono dati personali all’Agenzia procedono a tali trasferimenti solo per le finalità di cui al paragrafo 1. Qualunque trattamento di dati conservati per finalità diverse da quelle di cui al paragrafo 1 è vietato.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri o altri organismi, uffici e agenzie dell’Unione che forniscono dati personali all’Agenzia possono indicare, al momento del trasferimento di dati personali, le eventuali limitazioni di accesso o uso, in termini generali o specifici, anche per quanto concerne il trasferimento, la cancellazione o la distruzione. Qualora tali limitazioni si rendano necessarie dopo il trasferimento dei dati personali, lo Stato membro o l’organismo, l’ufficio o l’agenzia interessati ne informano l’Agenzia. L’Agenzia si conforma a tali limitazioni.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Trattamento dei dati personali per la prestazione di assistenza operativa e tecnica e a fini di reinsediamento", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il trattamento, da parte dell’Agenzia, di dati personali raccolti o trasmessile dagli Stati membri o dal suo personale nel contesto della prestazione di assistenza operativa e tecnica agli Stati membri e a fini di reinsediamento è limitato ai dati seguenti sui cittadini di paesi terzi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nome e cognome;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">data e luogo di nascita;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">luogo di residenza o dimora;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">genere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">età;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cittadinanza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">professione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">studi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">membri della famiglia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">data e luogo di arrivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impronte digitali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">immagine del volto; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">status in termini di protezione internazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia può trattare i dati personali di cui al paragrafo 1, ove necessario, per uno degli scopi seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per adottare misure operative e tecniche a norma dell’articolo 16, paragrafo 2, lettera a), b), c) g) o h);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per trasmettere tali dati personali all’Agenzia europea della guardia di frontiera e costiera, a Europol o Eurojust per lo svolgimento dei loro compiti in conformità ai rispettivi mandati e in conformità dell’articolo 30;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per trasmettere tali dati personali alle autorità nazionali competenti in materia di asilo e immigrazione nonché ad altri servizi pertinenti in conformità della legislazione nazionale e alle norme in materia di protezione dei dati nazionali e dell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per analizzare informazioni sulla situazione dell’asilo, come indicato all’articolo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per prestare assistenza agli Stati membri nelle azioni relative al reinsediamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ove strettamente necessario per una misura operativa e tecnica a norma dell’articolo 16, paragrafo 2, lettera c), o per le finalità di cui al paragrafo 2, lettera e), del presente articolo, l’Agenzia può, in relazione a un caso specifico, trattare i dati personali necessari per valutare se un cittadino di un paese terzo possa beneficiare della protezione internazionale e i dati relativi alla salute o a specifiche vulnerabilità di un cittadino di un paese terzo. Tali dati personali sono resi accessibili solo ai membri del personale che, nel caso specifico, necessitano di esserne a conoscenza. Tali membri del personale tutelano la riservatezza dei dati in questione. Tali dati personali non sono soggetti a ulteriore trattamento o a trasmissione ulteriore.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia cancella i dati personali subito dopo averli trasmessi all’Agenzia europea della guardia di frontiera e costiera, a Europol o Eurojust o alle autorità competenti nazionali o non appena siano stati utilizzati per analizzare le informazioni sulla situazione dell’asilo di cui all’articolo 5. In ogni caso il periodo di conservazione dei dati non supera 30 giorni dalla data in cui l’Agenzia raccoglie o riceve tali dati personali. L’Agenzia rende anonimi i dati personali contenuti nell’analisi delle informazioni sulla situazione dell’asilo di cui all’articolo 5.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia cancella i dati personali ottenuti per la finalità di cui all’articolo 31, paragrafo 1, lettera e) non appena non sono più necessari per la finalità per la quale sono stati ottenuti e, in ogni caso, entro 30 giorni dalla data di reinsediamento del cittadino del paese terzo.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Fatti salvi gli altri diritti sanciti dal regolamento (UE) 2016/679, e in aggiunta alle informazioni di cui all’articolo 13 di tale regolamento, gli esperti partecipanti alle squadre di sostegno per l’asilo che trasmettano dati personali a norma del paragrafo 1 del presente articolo forniscono ai cittadini di paesi terzi, al momento della raccolta dei loro dati personali, le informazioni di contatto dell’autorità di controllo incaricata di monitorare e garantire il rispetto di detto regolamento.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Cooperazione con la Danimarca", "anchor": "art_33", "frags": [[null, "<p class=\"oj-normal\">L’Agenzia agevola la cooperazione operativa con la Danimarca, incluso lo scambio di informazioni e di migliori prassi su questioni che rientrano nelle sue attività.</p>"]]}, "34": {"label": "Articolo 34", "heading": "Cooperazione con i paesi associati", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia è aperta alla partecipazione dell’Islanda, del Liechtenstein, della Norvegia e della Svizzera.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La natura, la portata e le modalità di partecipazione di Islanda, Liechtenstein, Norvegia e Svizzera ai lavori dell’Agenzia sono stabilite in pertinenti accordi operativi. Tali accordi operativi comprendono disposizioni relative alla partecipazione alle iniziative dell’Agenzia, ai contributi finanziari, alla partecipazione alle riunioni del consiglio d’amministrazione e al personale. In materia di personale, gli accordi operativi rispettano lo statuto dei funzionari dell’Unione europea («statuto») e il regime applicabile agli altri agenti dell’Unione europea («regime applicabile») definiti dal regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (<span class=\"oj-super oj-note-tag\">25</span>).</p>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Cooperazione con i paesi terzi", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per le questioni che rientrano nelle sue attività, e nella misura necessaria all’espletamento dei suoi compiti, l’Agenzia agevola e incoraggia la cooperazione operativa fra gli Stati membri e i paesi terzi nel quadro della politica dell’Unione in materia di relazioni esterne, anche per quanto concerne la tutela dei diritti fondamentali, e in cooperazione con il SEAE. L’Agenzia e gli Stati membri promuovono e osservano norme e standard che formano parte della normativa dell’Unione, anche quando svolgono attività nel territorio di paesi terzi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia può cooperare con le autorità di paesi terzi competenti per questioni contemplate nel presente regolamento, con il sostegno e di concerto con le delegazioni dell’Unione, in particolare per promuovere le norme dell’Unione in materia d’asilo, assistere i paesi terzi nell’acquisizione di competenze e nello sviluppo di capacità per i loro sistemi di asilo e di accoglienza, e attuare i programmi di sviluppo e protezione regionale e altre azioni. L’Agenzia può porre in atto tale cooperazione nell’ambito di accordi operativi conclusi con tali autorità, conformemente al diritto dell’Unione e alle sue politiche. Il consiglio d’amministrazione decide in merito a tali accordi operativi, che sono soggetti all’approvazione preliminare della Commissione. L’Agenzia informa il Parlamento europeo e il Consiglio prima della conclusione di un accordo operativo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel contesto della cooperazione con i paesi terzi, l’Agenzia può fornire sostegno a uno Stato membro ai fini dell’attuazione dei programmi di reinsediamento, su richiesta di tale Stato membro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nel quadro della politica esterna dell’Unione, ove opportuno, l’Agenzia partecipa all’attuazione degli accordi internazionali conclusi dall’Unione con i paesi terzi che riguardino i settori contemplati dal presente regolamento.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia può beneficiare del finanziamento dell’Unione ai sensi delle disposizioni dei pertinenti strumenti di sostegno alla politica esterna dell’Unione. L’Agenzia può varare e finanziare progetti di assistenza tecnica nei paesi terzi per le materie oggetto del presente regolamento.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’Agenzia informa il Parlamento europeo in merito alle attività espletate a norma del presente articolo per mezzo della sua relazione annuale sulla situazione dell’asilo nell’Unione di cui all’articolo 69. La relazione include anche una valutazione della cooperazione con i paesi terzi.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Funzionari di collegamento nei paesi terzi", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia può inviare nei paesi terzi esperti appartenenti al proprio personale. I funzionari di collegamento beneficiano della massima protezione possibile nell’esercizio delle loro funzioni in paesi terzi. I funzionari di collegamento sono inviati unicamente nei paesi terzi le cui prassi di gestione della migrazione e dell’asilo sono conformi alle norme inderogabili in materia di diritti umani.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel quadro della politica esterna dell’Unione, è data priorità all’invio di funzionari di collegamento nei paesi terzi che sono, in base all’analisi delle informazioni circa la loro situazione in materia d’asilo di cui all’articolo 5, paesi di origine o di transito di migrazione legata alle richieste d’asilo. L’invio di funzionari di collegamento è approvato dal consiglio d’amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Rientra tra i compiti dei funzionari di collegamento, in conformità con il diritto dell’Unione e rispettando pienamente i diritti fondamentali, instaurare e mantenere contatti con le autorità competenti dei paesi terzi presso i quali sono inviati per raccogliere informazioni, contribuire a mettere in atto una gestione della migrazione attenta alla protezione e, se del caso, facilitare l’accesso all’Unione mediante percorsi legali per le persone bisognose di protezione, anche attraverso il reinsediamento. I funzionari di collegamento operano in stretto coordinamento con le delegazioni dell’Unione e, ove opportuno, con le organizzazioni e gli organismi internazionali, in particolare l’UNHCR.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La decisione dell’Agenzia di inviare funzionari di collegamento in paesi terzi è soggetta al previo parere della Commissione. Il Parlamento europeo è di conseguenza tenuto informato tempestivamente e in modo esaustivo.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Cooperazione con gli organismi, gli uffici e le agenzie dell’Unione", "anchor": "art_37", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia coopera con gli organismi, gli uffici e le agenzie dell’Unione che svolgono attività legate al suo settore di competenza, in particolare con gli organismi, gli uffici e le agenzie nel settore della giustizia e degli affari interni che sono competenti nei settori contemplati dal presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La cooperazione di cui al paragrafo 1 si svolge, previo ottenimento dell’approvazione della Commissione, nell’ambito di accordi operativi conclusi con gli organismi, gli uffici e le agenzie dell’Unione di cui a detto paragrafo. L’Agenzia informa il Parlamento europeo e il Consiglio in merito a tali accordi operativi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La cooperazione di cui al paragrafo 1 consente di creare sinergie fra gli organismi, gli uffici e le agenzie rilevanti dell’Unione, ed evita la duplicazione degli sforzi nei lavori svolti da ciascun organo, ufficio o agenzia dell’Unione nell’ambito del proprio mandato.</p>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Cooperazione con l’UNHCR e con altre organizzazioni internazionali", "anchor": "art_38", "frags": [[null, "<p class=\"oj-normal\">L’Agenzia coopera con le organizzazioni internazionali, in particolare l’UNHCR, nei settori disciplinati dal presente regolamento, nell’ambito di accordi operativi conclusi con tali organizzazioni, conformemente ai trattati e agli strumenti che stabiliscono la competenza di tali organizzazioni. Il consiglio d’amministrazione decide in merito agli accordi operativi, che sono soggetti all’approvazione preliminare della Commissione. L’Agenzia informa il Parlamento europeo e il Consiglio in merito a tali accordi operativi.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Struttura amministrativa e di gestione", "anchor": "art_39", "frags": [[null, "<p class=\"oj-normal\">La struttura amministrativa e di gestione dell’Agenzia comprende:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un consiglio d’amministrazione, che esercita le funzioni definite all’articolo 41;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un direttore esecutivo, che esercita le responsabilità definite all’articolo 47;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un vicedirettore esecutivo, secondo quanto stabilito all’articolo 48;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un responsabile dei diritti fondamentali, secondo quanto stabilito all’articolo 49; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un forum consultivo, secondo quanto stabilito all’articolo 50.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "40": {"label": "Articolo 40", "heading": "Composizione del Consiglio d’amministrazione", "anchor": "art_40", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione è composto da un rappresentante di ciascuno Stato membro e da due rappresentanti della Commissione. Ciascuno di questi rappresentati ha diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione comprende un rappresentante dell’UNHCR. Tale rappresentante non ha diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ciascun membro del consiglio di amministrazione ha un supplente. Un supplente rappresenta un membro del consiglio d’amministrazione in caso d’assenza.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I membri del consiglio d’amministrazione e i loro supplenti sono nominati in base alle loro conoscenze e competenze in materia di asilo, tenendo conto delle pertinenti competenze gestionali, amministrative e di bilancio. Tutte le parti interessate si adoperano per conseguire una rappresentanza equilibrata di uomini e donne in seno al consiglio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il mandato dei membri del consiglio d’amministrazione è di quattro anni, ed è rinnovabile. Allo scadere del mandato o in caso di dimissioni i membri restano in carica fino a quando il loro mandato è rinnovato o fino alla loro sostituzione.</p>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Funzioni del consiglio d’amministrazione", "anchor": "art_41", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione definisce l’orientamento generale delle attività dell’Agenzia e garantisce che l’Agenzia svolga i suoi compiti. In particolare, il consiglio d’amministrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta il bilancio annuale dell’Agenzia a maggioranza di due terzi dei suoi membri con diritto di voto ed esercita altre funzioni in relazione al bilancio dell’Agenzia a norma del Capo 9;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la relazione annuale consolidata relativa alle attività dell’Agenzia, la trasmette al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti entro il 1<span class=\"oj-super\">o</span> luglio di ogni anno e la pubblica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le regole finanziarie applicabili all’Agenzia conformemente all’articolo 56;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta tutte le decisioni finalizzate all’esecuzione del mandato dell’Agenzia quale definito dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia antifrode, che è proporzionata al rischio di frode, tenendo conto dei costi e dei benefici delle misure da attuare nell’ambito di tale strategia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta norme di prevenzione e gestione dei conflitti di interesse in relazione ai suoi membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta e aggiorna regolarmente i piani di comunicazione e divulgazione di cui all’articolo 2, paragrafo 2, in base a un’analisi delle esigenze;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta il proprio regolamento interno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ai sensi del paragrafo 2, esercita, nei confronti del personale dell’Agenzia, i poteri conferiti dallo statuto dei funzionari all’autorità che ha il potere di nomina e dal regime applicabile all’autorità abilitata a concludere i contratti di assunzione («poteri dell’autorità che ha il potere di nomina»);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta idonee disposizioni di attuazione per dare effetto allo statuto dei funzionari e al regime applicabile, conformemente all’articolo 110 dello statuto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il direttore esecutivo e il vicedirettore esecutivo, esercita autorità disciplinare nei loro confronti e, se necessario, ne proroga il mandato o li rimuove dall’incarico, a norma degli articoli 46 o 48, se del caso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il responsabile dei diritti fondamentali, soggetto allo statuto e al regime applicabile agli altri agenti, da una rosa di candidati proposti dal direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un contabile, soggetto allo statuto e al regime applicabile agli altri agenti, che opera in piena indipendenza nell’esercizio delle sue funzioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la relazione annuale sulla situazione dell’asilo nell’Unione conformemente all’articolo 69;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta tutte le decisioni relative allo sviluppo dei sistemi informativi previsti dal presente regolamento, fra cui il portale d’informazioni di cui all’articolo 9, paragrafo 2, lettera b);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce le modalità pratiche di applicazione del regolamento (CE) n. 1049/2001 conformemente all’articolo 63 del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce le modalità di applicazione del regolamento (UE) 2018/1725 da parte dell’Agenzia, anche quelle in relazione alla nomina del responsabile della protezione dei dati dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la politica relativa al personale dell’Agenzia conformemente all’articolo 60;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta ogni anno il documento di programmazione dell’Agenzia conformemente all’articolo 42;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta tutte le decisioni relative alla costituzione della struttura interna dell’Agenzia e, ove necessario, alla loro modifica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicura un seguito adeguato alle osservazioni e alle raccomandazioni risultanti dalle relazioni di audit e valutazioni interne ed esterne e dalle indagini dell’Ufficio europeo per la lotta antifrode (OLAF);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le norme operative, gli indicatori, gli orientamenti e le migliori prassi sviluppati dall’Agenzia conformemente all’articolo 13, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">approva le note di orientamento relative alle informazioni sui paesi d’origine e le revisioni o gli aggiornamenti di tali note di orientamento conformemente all’articolo 11, paragrafi 2 e 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una decisione che stabilisce una metodologia comune per il meccanismo di monitoraggio di cui all’articolo 14;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta il programma di monitoraggio dell’applicazione operativa e tecnica del CEAS conformemente all’articolo 15, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le raccomandazioni a seguito del monitoraggio conformemente all’articolo 15, paragrafo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">aa)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide i profili e il numero totale di esperti da mettere a disposizione delle squadre di sostegno per l’asilo e del gruppo di riserva in materia d’asilo, a norma dell’articolo 19, paragrafi 2 e 6;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ab)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia per le relazioni con i paesi terzi o le organizzazioni internazionali riguardo alle questioni che rientrano nelle competenze dell’Agenzia così come un accordo operativo con la Commissione per la sua attuazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ac)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorizza e approva la conclusione di accordi operativi conformemente agli articoli 35, 37 e 38.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione adotta, in conformità all’articolo 110 dello statuto, una decisione basata sull’articolo 2, paragrafo 1, dello statuto dei funzionari e sull’articolo 6 del regime applicabile, con cui delega al direttore esecutivo i poteri dell’autorità che ha il potere di nomina e stabilisce le condizioni di sospensione della delega di poteri dell’autorità che ha il potere di nomina. Il direttore esecutivo è autorizzato a subdelegare i poteri dell’autorità che ha il potere di nomina.</p>\n<p class=\"oj-normal\">Qualora circostanze eccezionali lo richiedano, il consiglio d’amministrazione può, mediante decisione, sospendere temporaneamente i poteri dell’autorità che ha il potere di nomina delegati al direttore esecutivo e quelli subdelegati da quest’ultimo, ed esercitarli esso stesso o delegarli a uno dei suoi membri o a un membro del personale diverso dal direttore esecutivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio d’amministrazione può istituire un comitato esecutivo ristretto per assistere il consiglio stesso e il direttore esecutivo nel predisporre le decisioni, i programmi e le attività che saranno adottati dal consiglio d’amministrazione. Ove necessario, il comitato esecutivo può prendere decisioni urgenti provvisorie per conto del consiglio d’amministrazione, in particolare su questioni di gestione amministrativa. Il comitato esecutivo non adotta decisioni che richiedono una maggioranza dei due terzi o dei tre quarti dei membri del consiglio d’amministrazione. Il consiglio d’amministrazione può delegare determinati compiti chiaramente definiti al comitato esecutivo, in particolare quando tale delega migliorerebbe l’efficacia dell’Agenzia. Il consiglio d’amministrazione non delega al comitato esecutivo compiti collegati a decisioni che richiedono una maggioranza dei due terzi o dei tre quarti dei membri del consiglio d’amministrazione. Ai fini dell’istituzione del comitato esecutivo, il consiglio d’amministrazione adotta il proprio regolamento interno. Tale regolamento interno, in particolare, riguarda la composizione e le funzioni del comitato esecutivo.</p>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Programmazione pluriennale e programmi di lavoro annuali", "anchor": "art_42", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione trasmette una bozza del documento di programmazione contenente la programmazione pluriennale e annuale, in base a un progetto presentato dal direttore esecutivo, al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno. Analogamente il consiglio d’amministrazione trasmette ogni eventuale versione successiva aggiornata del documento di programmazione al Parlamento europeo, al Consiglio e alla Commissione.</p>\n<p class=\"oj-normal\">Entro il 30 novembre di ogni anno il consiglio d’amministrazione adotta, a maggioranza dei due terzi dei suoi membri con diritto di voto, il documento di programmazione tenendo conto del parere della Commissione e, nel caso della programmazione pluriennale, previa consultazione del Parlamento europeo. Il consiglio d’amministrazione trasmette il documento di programmazione al Parlamento europeo, al Consiglio e alla Commissione.</p>\n<p class=\"oj-normal\">Il documento di programmazione diventa definitivo dopo l’approvazione definitiva del bilancio generale dell’Unione e, se necessario, è adeguato di conseguenza.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La programmazione pluriennale definisce la programmazione strategica generale a medio e a lungo termine, compresi gli obiettivi, i risultati attesi e gli indicatori di risultato. La programmazione pluriennale riporta inoltre la programmazione delle risorse, compresi un bilancio pluriennale e organico.</p>\n<p class=\"oj-normal\">La programmazione pluriennale stabilisce i settori strategici di intervento e illustra le azioni necessarie per conseguire gli obiettivi ivi stabiliti. La programmazione pluriennale comprende la strategia per le relazioni con i paesi terzi e le organizzazioni internazionali di cui agli articoli 35 e 38, rispettivamente, le azioni connesse a tale strategia e una specificazione delle risorse associate.</p>\n<p class=\"oj-normal\">La programmazione pluriennale è attuata attraverso programmi di lavoro annuali. Viene aggiornata annualmente se del caso, in particolare in base all’esito della valutazione di cui all’articolo 70.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il programma di lavoro annuale comprende gli obiettivi dettagliati e i risultati attesi, compresi gli indicatori di risultato. Il programma di lavoro annuale contiene inoltre una descrizione delle azioni da finanziare, e un’indicazione delle risorse finanziarie e umane assegnate a ciascuna attività, in conformità ai principi di formazione del bilancio per attività e gestione per attività. Il programma di lavoro annuale è coerente con la programmazione pluriennale di cui al paragrafo 2. Il programma di lavoro annuale indica chiaramente i compiti aggiunti, modificati o soppressi rispetto all’esercizio finanziario precedente.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Quando all’Agenzia viene affidato un nuovo compito, il consiglio d’amministrazione modifica il programma di lavoro annuale.</p>\n<p class=\"oj-normal\">Le modifiche sostanziali del programma di lavoro annuale sono adottate con la stessa procedura del programma di lavoro annuale iniziale. Il consiglio d’amministrazione può delegare al direttore esecutivo il potere di presentare modifiche non sostanziali del programma di lavoro annuale.</p>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Presidente del consiglio d’amministrazione", "anchor": "art_43", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione elegge un presidente e un vicepresidente scegliendoli tra i suoi membri con diritto di voto. Il presidente e il vicepresidente sono eletti a maggioranza di due terzi dei membri del consiglio d’amministrazione con diritto di voto.</p>\n<p class=\"oj-normal\">Il vicepresidente sostituisce automaticamente il presidente in caso di impedimento di quest’ultimo a svolgere le sue funzioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il presidente e il vicepresidente hanno un mandato di quattro anni rinnovabile un’unica volta. Tuttavia, se cessano di far parte del consiglio d’amministrazione in un qualsiasi momento del mandato da presidente o vicepresidente, questo termina automaticamente alla stessa data.</p>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Riunioni del consiglio d’amministrazione", "anchor": "art_44", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le riunioni del consiglio d’amministrazione sono indette dal presidente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo partecipa alle deliberazioni del consiglio d’amministrazione, senza diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il rappresentante dell’UNHCR non partecipa alle riunioni nelle quali il consiglio d’amministrazione svolge le funzioni di cui all’articolo 41, paragrafo 1, lettera e), f), i), j), k), p), r), s), t) o u) e all’articolo 41, paragrafo 2, e quando il consiglio d’amministrazione mette a disposizione risorse finanziarie per finanziare azioni dell’UNHCR, come previsto all’articolo 52, per consentire all’Agenzia di beneficiare della competenza dell’UNHCR.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d’amministrazione tiene almeno due riunioni ordinarie all’anno. Il consiglio d’amministrazione si riunisce inoltre su istanza del presidente, su richiesta della Commissione o su richiesta di un terzo dei suoi membri.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio d’amministrazione può invitare a partecipare alle sue riunioni, in veste di osservatore, ogni persona il cui parere possa essere rilevante.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   La Danimarca è invitata a inviare un rappresentante per partecipare alle riunioni del consiglio d’amministrazione.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   I membri e i supplenti del consiglio d’amministrazione, fatto salvo il suo regolamento interno, possono farsi assistere nelle riunioni da consulenti o esperti.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L’Agenzia provvede alle funzioni di segreteria del consiglio d’amministrazione.</p>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Regole di voto del consiglio d’amministrazione", "anchor": "art_45", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Salvo disposizioni contrarie, il consiglio d’amministrazione decide a maggioranza assoluta dei membri aventi diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni membro avente diritto di voto dispone di un voto. In assenza di un membro con diritto di voto, il suo supplente è abilitato a esercitare il diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il presidente partecipa al voto.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo non partecipa al voto.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I rappresentanti degli Stati membri che non partecipano all’integralità dell’acquis dell’Unione in materia di asilo non prendono parte al voto qualora il consiglio d’amministrazione debba adottare norme operative, indicatori, orientamenti o migliori prassi che riguardano esclusivamente uno strumento dell’Unione in materia di asilo da cui gli Stati membri che essi rappresentano non sono vincolati.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il regolamento interno del consiglio d’amministrazione stabilisce le regole dettagliate concernenti la votazione, in particolare le circostanze in cui un membro può agire per conto di un altro.</p>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Direttore esecutivo", "anchor": "art_46", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è un membro del personale ed è assunto come agente temporaneo dell’Agenzia a norma dell’articolo 2, lettera a), del regime applicabile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione propone almeno tre candidati per il posto di direttore esecutivo sulla base di un elenco, successivamente alla pubblicazione del posto nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span> ed eventualmente sulla stampa o su siti Internet.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio d’amministrazione nomina il direttore esecutivo sulla base del merito, della provata competenza di alto livello in materia amministrativa e gestionale e della estesa esperienza professionale in materia di migrazione ed asilo. Prima della nomina, i candidati proposti dalla Commissione sono invitati a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di detta commissione o dette commissioni.</p>\n<p class=\"oj-normal\">A seguito di tale dichiarazione il Parlamento europeo adotta un parere nel quale espone la sua opinione e può esprimere una preferenza per un candidato.</p>\n<p class=\"oj-normal\">Il consiglio d’amministrazione nomina il direttore esecutivo tenendo conto del parere del Parlamento europeo di cui al secondo comma.</p>\n<p class=\"oj-normal\">Se il consiglio d’amministrazione decide di nominare un candidato diverso da quello per il quale il Parlamento europeo aveva espresso una preferenza, informa per iscritto il Parlamento europeo e il Consiglio del modo in cui è stato tenuto conto del parere del Parlamento europeo.</p>\n<p class=\"oj-normal\">Ai fini della conclusione del contratto con il direttore esecutivo, l’Agenzia è rappresentata dal presidente del consiglio d’amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La durata del mandato del direttore esecutivo è di cinque anni. Entro la fine di tale periodo, la Commissione effettua una valutazione che tiene conto dei risultati ottenuti dal direttore esecutivo, nonché dei compiti e delle sfide futuri dell’Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Agendo su proposta della Commissione, la quale tiene conto della valutazione di cui al paragrafo 4, il consiglio d’amministrazione può prorogare il mandato del direttore esecutivo una sola volta per non più di cinque anni.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio d’amministrazione informa il Parlamento europeo dell’intenzione di prorogare il mandato del direttore esecutivo. Entro il periodo di un mese precedente tale proroga, il direttore esecutivo può essere invitato a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di detta commissione o dette commissioni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Un direttore esecutivo il cui mandato sia stato prorogato non partecipa a un’altra procedura di selezione per lo stesso posto alla fine del periodo complessivo.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo può essere rimosso dal suo incarico solo su decisione del consiglio d’amministrazione adottata su proposta della Commissione.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il consiglio d’amministrazione adotta le decisioni riguardanti la nomina del direttore esecutivo, la proroga del suo mandato e la sua rimozione dall’incarico a maggioranza di due terzi dei suoi membri con diritto di voto.</p>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Responsabilità del direttore esecutivo", "anchor": "art_47", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo assicura la gestione dell’Agenzia e risponde delle sue attività al consiglio d’amministrazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le competenze della Commissione e del consiglio d’amministrazione, il direttore esecutivo esercita le sue funzioni in piena indipendenza e non sollecita né accetta istruzioni da alcun governo, istituzione, persona o altro organismo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Su richiesta, il direttore esecutivo riferisce al Parlamento europeo sull’esercizio delle sue funzioni. Il Consiglio può invitare il direttore esecutivo a presentare una relazione sull’esercizio delle sue funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo è il rappresentante legale dell’Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo è responsabile dell’esecuzione dei compiti assegnati all’Agenzia dal presente regolamento. In particolare il direttore esecutivo è responsabile di quanto segue:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la gestione corrente dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’attuazione delle decisioni adottate dal consiglio d’amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la preparazione dei documenti di programmazione di cui all’articolo 42 e la loro presentazione al consiglio d’amministrazione previa consultazione della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’attuazione dei documenti di programmazione di cui all’articolo 42 e il rendiconto di tale attuazione al consiglio d’amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’elaborazione delle relazioni annuali consolidate di attività dell’Agenzia e la loro presentazione al consiglio d’amministrazione per adozione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’elaborazione di un piano d’azione volto a dare seguito alle conclusioni delle relazioni di audit e valutazioni interne ed esterne e alle indagini dell’OLAF, e il rendiconto sui progressi compiuti, due volte all’anno alla Commissione e periodicamente al consiglio di amministrazione e, se del caso, al comitato esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la tutela degli interessi finanziari dell’Unione mediante l’applicazione di misure di prevenzione contro le frodi, la corruzione e qualsiasi altra attività illecita, fatti salvi i poteri investigativi dell’OLAF, attraverso controlli effettivi e, nel caso in cui siano riscontrate irregolarità, il recupero delle somme indebitamente corrisposte nonché, se del caso, mediante l’applicazione di sanzioni amministrative e pecuniarie effettive, proporzionate e dissuasive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’elaborazione di una strategia antifrode dell’Agenzia e la sua presentazione al consiglio d’amministrazione per approvazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la preparazione del progetto di regole finanziarie applicabili all’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’elaborazione dei progetti di stato di previsione delle entrate e delle spese dell’Agenzia conformemente all’articolo 53 e l’esecuzione del bilancio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’esercizio delle competenze di cui all’articolo 60 nei confronti del personale dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’adozione di tutte le decisioni relative alla gestione dei sistemi informativi previsti dal presente regolamento, fra cui il portale d’informazioni di cui all’articolo 9, paragrafo 2, lettera b);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’adozione di tutte le decisioni relative alla gestione delle strutture interne dell’Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’elaborazione di relazioni sulla situazione nei paesi terzi di cui all’articolo 9;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la presentazione dell’analisi comune e delle note di orientamento al consiglio d’amministrazione conformemente all’articolo 11, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la creazione di squadre di esperti ai fini degli articoli 14 e 15, composte da esperti appartenenti al personale dell’Agenzia, della Commissione e, se necessario, degli Stati membri e, in qualità di osservatore, dell’UNHCR;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’avvio di una procedura di monitoraggio conformemente all’articolo 15, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la presentazione dei risultati e delle bozze di raccomandazioni, nel contesto di una procedura di monitoraggio, allo Stato membro interessato e successivamente al consiglio d’amministrazione conformemente all’articolo 15, paragrafi 3 e 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la presentazione di relazioni al consiglio d’amministrazione e alla Commissione conformemente all’articolo 4, paragrafo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la valutazione, l’approvazione e il coordinamento delle richieste di assistenza operativa e tecnica conformemente all’articolo 16, paragrafo 1, e all’articolo 20;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’attuazione dei piani operativi di cui all’articolo 18;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il coordinamento delle attività delle squadre di sostegno per la gestione della migrazione con la Commissione e altri organismi, uffici e agenzie competenti dell’Unione conformemente all’articolo 21, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’attuazione delle decisioni del Consiglio di cui all’articolo 22, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le decisioni, in consultazione con il consiglio d’amministrazione, riguardanti l’acquisto o il noleggio di attrezzature tecniche conformemente all’articolo 23, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la proposta di una rosa di candidati per la nomina a responsabile dei diritti fondamentali conformemente all’articolo 49, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la nomina di un agente di coordinamento dell’Agenzia conformemente all’articolo 25, paragrafo 2.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Vicedirettore esecutivo", "anchor": "art_48", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è assistito da un vicedirettore esecutivo nella gestione dell’Agenzia e nello svolgimento dei compiti di cui all’articolo 47, paragrafo 5. In caso di assenza o indisponibilità del direttore esecutivo, il vicedirettore esecutivo ne fa le veci.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione nomina il vicedirettore esecutivo su proposta del direttore esecutivo. Il direttore esecutivo è nominato dal consiglio d’amministrazione sulla base del merito, della provata competenza di alto livello in materia amministrativa e gestionale e della estesa esperienza professionale in materia di asilo. Il direttore esecutivo propone almeno tre candidati per il posto di vicedirettore esecutivo. Il consiglio d’amministrazione ha il potere di prorogare il mandato del vicedirettore esecutivo o di rimuoverlo dal suo incarico su proposta del direttore esecutivo. Al vicedirettore esecutivo si applica mutatis mutandis l’articolo 46, paragrafi 1), 4), 7) e 9).</p>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Responsabile dei diritti fondamentali", "anchor": "art_49", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione nomina un responsabile dei diritti fondamentali da una rosa di candidati proposti dal direttore esecutivo. Il responsabile dei diritti fondamentali dispone delle qualifiche e dell’esperienza necessarie nel settore dei diritti fondamentali e dell’asilo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il responsabile dei diritti fondamentali è indipendente nell’espletamento delle sue funzioni e riferisce direttamente al consiglio d’amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il responsabile dei diritti fondamentali ha il compito di assicurare il rispetto dei diritti fondamentali da parte dell’Agenzia nello svolgimento di tutte le attività e di promuovere il rispetto di tali diritti da parte dell’Agenzia. Il responsabile dei diritti fondamentali è inoltre competente per l’attuazione del meccanismo di denuncia di cui all’articolo 51.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il responsabile dei diritti fondamentali coopera con il forum consultivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il responsabile dei diritti fondamentali è consultato, tra l’altro, in merito ai piani operativi di cui all’articolo 18, alla valutazione dell’assistenza operativa e tecnica dell’Agenzia, al codice di condotta di cui all’articolo 58 e al programma europeo in materia di asilo di cui all’articolo 8, paragrafo 3. Il responsabile dei diritti fondamentali ha accesso a tutte le informazioni riguardanti il rispetto dei diritti fondamentali in relazione a tutte le attività dell’Agenzia, anche mediante l’organizzazione di visite, con il consenso dello Stato membro interessato, nei luoghi in cui l’Agenzia effettua attività operative.</p>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Forum consultivo", "anchor": "art_50", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia mantiene uno stretto dialogo con le pertinenti organizzazioni della società civile e i relativi organismi competenti che operano nel settore della politica di asilo a livello locale, regionale, nazionale, europeo o internazionale e istituisce a tal fine un forum consultivo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il forum consultivo costituisce un meccanismo di scambio di informazioni e la condivisione di conoscenze. Il forum consultivo assicura uno stretto dialogo tra l’Agenzia e le organizzazioni o gli organismi pertinenti di cui al paragrafo 1.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia invita l’Agenzia dell’Unione europea per i diritti fondamentali, l’Agenzia europea della guardia di frontiera e costiera, l’UNHCR e le altre organizzazioni e organismi pertinenti di cui al paragrafo 1 a divenire membri del forum consultivo.</p>\n<p class=\"oj-normal\">Su proposta del direttore esecutivo, il consiglio d’amministrazione decide in merito alla composizione del forum consultivo, compresi i gruppi consultivi di impostazione tematica o geografica, e alle condizioni di comunicazione delle informazioni al forum consultivo. Il forum consultivo, previa consultazione con il consiglio d’amministrazione e con il direttore esecutivo, stabilisce le proprie metodologie di lavoro, compresi gruppi di lavoro di impostazione tematica o geografica ritenuti necessari e utili.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il forum consultivo fornisce orientamenti al direttore esecutivo e al consiglio d’amministrazione sulle questioni attinenti all’asilo, conformemente alle specifiche esigenze dell’Agenzia nei settori individuati come prioritari per il suo lavoro.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il forum consultivo, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">formula proposte al consiglio d’amministrazione sulla programmazione annuale e pluriennale di cui all’articolo 42;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce un riscontro al consiglio d’amministrazione e propone il seguito da dare alla relazione annuale sulla situazione dell’asilo nell’Unione di cui all’articolo 69; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">comunica al direttore esecutivo e al consiglio d’amministrazione i risultati e le raccomandazioni delle conferenze, dei seminari e delle riunioni, e i risultati di studi o di lavori sul campo svolti da organizzazioni od organismi membri del forum consultivo, e pertinenti per i lavori dell’Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il forum consultivo è consultato sulla preparazione, l’adozione e l’attuazione della strategia in materia di diritti fondamentali di cui all’articolo 57, paragrafo 3, e sui codici di condotta di cui all’articolo 58, sull’istituzione del meccanismo di denuncia di cui all’articolo 51 e sullo sviluppo del programma europeo di formazione in materia di asilo di cui all’articolo 8, paragrafo 3.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il forum consultivo si riunisce in sessione plenaria almeno una volta all’anno e organizza riunioni per i gruppi consultivi di impostazione tematica o geografica, ove necessario.</p>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Meccanismo di denuncia", "anchor": "art_51", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia istituisce un meccanismo di denuncia inteso ad assicurare che i diritti fondamentali siano rispettati in tutte le attività dell’Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualsiasi persona che sia direttamente interessata dalle azioni di un esperto che partecipa a una squadra di sostegno per l’asilo e che ritenga di essere stata oggetto di una violazione dei suoi diritti fondamentali a seguito di tali azioni, o un terzo che rappresenta tale persona, può presentare una denuncia per iscritto all’Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Solo le denunce comprovate riguardanti violazioni concrete dei diritti fondamentali sono ricevibili. Le denunce che impugnino una decisione di un’autorità nazionale su singole domande di protezione internazionale sono irricevibili. Le denunce anonime, futili, improprie, vessatorie, ipotetiche, imprecise o presentate in malafede sono anch’esse irricevibili.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il responsabile dei diritti fondamentali è competente per la gestione delle denunce ricevute dall’Agenzia e agisce in conformità del diritto a una buona amministrazione. A tal fine, il responsabile dei diritti fondamentali:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esamina la ricevibilità delle denunce;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">registra le denunce ricevibili;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">inoltra le denunce ricevute al direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">trasmette allo Stato membro di origine le denunce riguardanti gli esperti che partecipano ad una squadra di sostegno per l’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informa l’autorità o l’organo competenti in materia di diritti fondamentali di uno Stato membro di una denuncia; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">registra e assicura il seguito dato alla denuncia dall’Agenzia o dallo Stato membro interessato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   In conformità con il diritto a una buona amministrazione, ove una denuncia sia ricevibile, il denunciante è informato del fatto che la denuncia è stata registrata, che è stata avviata una valutazione e che riceverà una risposta non appena sarà disponibile. Se la denuncia è trasmessa a un’autorità o organo nazionale, il denunciante ne riceve le informazioni di contatto. Qualora la denuncia sia irricevibile, il denunciante è informato dei motivi di irricevibilità e riceve, ove possibile, informazioni sulle soluzioni alternative per affrontare il suo problema. Ogni decisione è redatta per iscritto ed è motivata.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nel caso di una denuncia registrata nei confronti di un membro del personale dell’Agenzia, il direttore esecutivo assicura un seguito appropriato, in consultazione con il responsabile dei diritti fondamentali, comprese misure disciplinari se necessario. Il direttore esecutivo riferisce al responsabile dei diritti fondamentali, entro un termine stabilito, in merito ai risultati e al seguito dato dall’Agenzia alla denuncia, comprese le eventuali misure disciplinari.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Se la denuncia è legata a questioni relative alla protezione dei dati, il direttore esecutivo coinvolge il responsabile della protezione dei dati dell’Agenzia. Il responsabile dei diritti fondamentali e il responsabile della protezione dei dati concludono per iscritto un protocollo d’intesa, precisando la ripartizione dei loro compiti e le modalità della loro cooperazione in relazione alle denunce ricevute.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Nel caso di una denuncia riguardante un esperto di uno Stato membro, compresi gli esperti nazionali distaccati, lo Stato membro di origine assicura un seguito appropriato, comprese, se necessarie, misure disciplinari o altre misure in conformità del diritto nazionale. Lo Stato membro di origine riferisce al responsabile dei diritti fondamentali in merito ai risultati e il seguito dato alla denuncia entro un determinato periodo e successivamente, se necessario, a intervalli regolari. L’Agenzia dà seguito alla questione se non riceve alcuna informazione in proposito dallo Stato membro di origine.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Qualora sia stata accertata una violazione dei diritti fondamentali o degli obblighi di protezione internazionale da parte di un esperto inviato da uno Stato membro, compresi gli esperti nazionali distaccati, il direttore esecutivo chiede allo Stato membro di allontanare immediatamente l’esperto o l’esperto nazionale distaccato dalle attività dell’Agenzia. Qualora si accerti una violazione dei diritti fondamentali o degli obblighi di protezione internazionale da parte di un esperto inviato dall’Agenzia, il direttore esecutivo allontana tale esperto dalle attività dell’Agenzia.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il responsabile dei diritti fondamentali riferisce al direttore esecutivo e al consiglio d’amministrazione in merito ai risultati e al seguito dato a una denuncia da parte dell’Agenzia e degli Stati membri interessati. L’Agenzia include nella sua relazione annuale sulla situazione dell’asilo nell’Unione informazioni riguardanti il meccanismo di denuncia di cui all’articolo 69.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   L’Agenzia, incluso il responsabile dei diritti fondamentali, gestisce e tratta i dati personali contenuti in una denuncia in conformità del regolamento (UE) 2018/1725.Gli Stati membri gestiscono e trattano i dati personali contenuti in una denuncia in conformità del regolamento (UE) 2016/679 o della direttiva (UE) 2016/680, se del caso. Ogniqualvolta un denunciante presenta una denuncia, si considera che esso abbia acconsentito al trattamento dei suoi dati personali da parte dell’Agenzia e del responsabile dei diritti fondamentali ai sensi dell’articolo 5, paragrafo 1, lettera d), del regolamento (UE) 2018/1725. Al fine di tutelare gli interessi dei denuncianti, il responsabile dei diritti fondamentali tratta le denunce con riservatezza conformemente al diritto nazionale e dell’Unione, a meno che il denunciante non rinunci esplicitamente al proprio diritto alla riservatezza. Se rinuncia al diritto alla riservatezza, si considera che un denunciante abbia accettato che il responsabile dei diritti fondamentali o l’Agenzia ne divulghi l’identità, se necessario, alle autorità o agli organi competenti in relazione all’oggetto della denuncia.</p>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Bilancio", "anchor": "art_52", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le entrate e le spese dell’Agenzia sono oggetto di previsioni per ciascun esercizio finanziario, che coincide con l’anno civile, e sono iscritte nel bilancio dell’Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le entrate e le spese iscritte nel bilancio dell’Agenzia devono essere in pareggio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatte salve altre risorse, le entrate dell’Agenzia comprendono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dell’Unione iscritto al bilancio generale dell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">finanziamenti dell’Unione in regime di gestione indiretta o sotto forma sovvenzioni ad hoc ai sensi delle regole finanziarie applicabili all’Agenzia e delle disposizioni dei pertinenti strumenti di sostegno alle politiche dell’Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">eventuali contributi finanziari volontari degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">eventuali contributi dei paesi associati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i diritti percepiti per pubblicazioni o qualsiasi altro servizio fornito dall’Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le spese dell’Agenzia comprendono le retribuzioni del personale, le spese amministrative e di infrastruttura e le spese di esercizio.</p>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Stesura del bilancio", "anchor": "art_53", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni anno il direttore esecutivo predispone un progetto di stato di previsione delle entrate e delle spese dell’Agenzia per l’esercizio finanziario successivo, che comprende la tabella dell’organico, e lo trasmette al consiglio d’amministrazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Sulla base del progetto di stato di previsione di cui al paragrafo 1, il consiglio d’amministrazione prepara un progetto di stato di previsione delle entrate e delle spese dell’Agenzia per l’esercizio finanziario successivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il progetto di stato di previsione delle entrate e delle spese dell’Agenzia di cui al paragrafo 2 è trasmesso alla Commissione, al Parlamento europeo e al Consiglio entro il 31 gennaio di ogni anno.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione trasmette lo stato di previsione all’autorità di bilancio con il progetto di bilancio generale dell’Unione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base di tale stato di previsione, la Commissione inserisce nel progetto di bilancio generale dell’Unione le previsioni ritenute necessarie per la tabella dell’organico nonché l’importo del contributo a carico dell’Unione da iscrivere al bilancio generale, che sottopone all’autorità di bilancio a norma degli articoli 313 e 314 TFUE.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’autorità di bilancio autorizza gli stanziamenti a titolo di contributo a carico dell’Unione destinato all’Agenzia.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L’autorità di bilancio adotta la tabella dell’organico dell’Agenzia.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio d’amministrazione adotta il bilancio dell’Agenzia. Il bilancio dell’Agenzia diventa definitivo dopo l’adozione definitiva del bilancio generale dell’Unione. Se del caso, il bilancio dell’Agenzia è opportunamente adeguato.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Ai progetti riguardanti gli immobili che possono avere implicazioni significative per il bilancio dell’Agenzia si applica il regolamento delegato (UE) 2019/715.</p>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Esecuzione del bilancio", "anchor": "art_54", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è responsabile dell’esecuzione del bilancio dell’Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo trasmette ogni anno all’autorità di bilancio qualsiasi informazione rilevante in relazione ai risultati delle procedure di valutazione.</p>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Rendicontazione e discarico", "anchor": "art_55", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 1<span class=\"oj-super\">o</span> marzo dell’esercizio finanziario N + 1, il contabile dell’Agenzia invia al contabile della Commissione e alla Corte dei conti i conti provvisori per l’esercizio finanziario N.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 31 marzo dell’esercizio finanziario N + 1, l’Agenzia trasmette la relazione sulla gestione finanziaria e di bilancio per l’esercizio finanziario N al Parlamento europeo, al Consiglio e alla Corte dei conti.</p>\n<p class=\"oj-normal\">Entro il 31 marzo dell’esercizio finanziario N + 1, il contabile della Commissione trasmette i conti provvisori dell’Agenzia per l’esercizio finanziario N, consolidati con i conti della Commissione, alla Corte dei conti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Al ricevimento delle osservazioni formulate dalla Corte dei conti sui conti provvisori dell’Agenzia ai sensi dell’articolo 246 del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">26</span>), il direttore esecutivo stabilisce i conti definitivi dell’Agenzia per l’esercizio finanziario N sotto la propria responsabilità e li presenta al consiglio d’amministrazione per parere.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d’amministrazione formula un parere sui conti definitivi dell’Agenzia per l’esercizio finanziario N.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Entro il 1<span class=\"oj-super\">o</span> luglio dell’esercizio finanziario N + 1, il direttore esecutivo trasmette i conti definitivi per l’esercizio finanziario N, unitamente al parere del consiglio d’amministrazione, al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   I conti definitivi per l’esercizio finanziario N sono pubblicati nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span> entro il 15 novembre dell’esercizio finanziario N + 1.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro il 30 settembre dell’esercizio finanziario N + 1, il direttore esecutivo invia alla Corte dei conti una risposta alle osservazioni di quest’ultima. Invia inoltre tale risposta al consiglio d’amministrazione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo presenta al Parlamento europeo, su richiesta dello stesso e a norma dell’articolo 261, paragrafo 3, del regolamento (UE, Euratom) 2018/1046, tutte le informazioni necessarie per il corretto svolgimento della procedura di discarico per l’esercizio finanziario in oggetto.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà discarico al direttore esecutivo dell’Agenzia, prima del 15 maggio dell’esercizio finanziario n + 2, per l’esecuzione del bilancio per l’esercizio finanziario N.</p>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Regole finanziarie", "anchor": "art_56", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio d’amministrazione adotta le regole finanziarie applicabili all’Agenzia previa consultazione della Commissione. Le regole finanziarie sono conformi al regolamento delegato (UE) 2019/715, tranne nel caso in cui una deroga a tale regolamento sia richiesta dalle esigenze specifiche di funzionamento dell’Agenzia e previo accordo della Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia può concedere sovvenzioni legate all’espletamento dei compiti di cui all’articolo 2 del presente regolamento e ricorrere a contratti quadro conformemente al presente regolamento o su delega della Commissione a norma dell’articolo 62, paragrafo 1, lettera c), punto iv) del regolamento (UE, Euratom) 2018/1046. Si applicano le pertinenti disposizioni del regolamento (UE, Euratom) 2018/1046.</p>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Protezione dei diritti fondamentali e strategia in materia di diritti fondamentali", "anchor": "art_57", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia garantisce la tutela dei diritti fondamentali nell’esecuzione dei suoi compiti a norma del presente regolamento in conformità del pertinente diritto dell’Unione, ivi compresi la Carta, e del diritto internazionale pertinente, in particolare la Convenzione di Ginevra relativa allo status dei rifugiati del 28 luglio 1951, modificata dal protocollo di New York del 31 gennaio 1967.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’interesse superiore del minore costituisce una considerazione preminente nell’applicazione del presente regolamento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia, su proposta del responsabile dei diritti fondamentali, adotta e attua una strategia in materia di diritti fondamentali onde garantire il rispetto di tali diritti in tutte le proprie attività.</p>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Codice di condotta", "anchor": "art_58", "frags": [[null, "<p class=\"oj-normal\">L’Agenzia sviluppa, adotta e attua un codice di condotta applicabile a tutti gli esperti partecipanti alle squadre di sostegno per l’asilo. Il codice di condotta stabilisce procedure intese a garantire i principi dello Stato di diritto e il rispetto dei diritti fondamentali, con particolare attenzione al caso dei minori, dei minori non accompagnati e delle altre persone vulnerabili.</p>"]]}, "59": {"label": "Articolo 59", "heading": "Status giuridico", "anchor": "art_59", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia è un’agenzia dell’Unione. L’Agenzia ha personalità giuridica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia gode in tutti gli Stati membri della più ampia capacità giuridica riconosciuta alle persone giuridiche dalle rispettive legislazioni. L’Agenzia può in particolare acquisire o alienare beni mobili e immobili e stare in giudizio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Agenzia è indipendente per quanto attiene alle questioni tecniche e operative.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia è rappresentata dal direttore esecutivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia ha sede a Malta.</p>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Personale", "anchor": "art_60", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al personale dell’Agenzia si applicano lo statuto dei funzionari, il regime applicabile e le regole adottate di comune accordo dalle istituzioni dell’Unione europea per l’applicazione dello statuto e del regime applicabile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio d’amministrazione adotta idonee disposizioni di attuazione per dare effetto allo statuto dei funzionari e al regime applicabile, a norma dell’articolo 110 dello statuto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei confronti del proprio personale, l’Agenzia esercita i poteri conferiti all’autorità investita del potere di nomina.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Agenzia può avvalersi di esperti nazionali distaccati o di altro personale non alle sue dipendenze. Il consiglio d’amministrazione adotta una decisione in cui stabilisce le norme relative al distacco di esperti nazionali presso l’Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Agenzia può impiegare personale per lavorare sul campo negli Stati membri.</p>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Privilegi e immunità", "anchor": "art_61", "frags": [[null, "<p class=\"oj-normal\">All’Agenzia e al suo personale si applica il protocollo n. 7 sui privilegi e sulle immunità dell’Unione europea allegati al TUE e al TFUE.</p>"]]}, "62": {"label": "Articolo 62", "heading": "Regime linguistico", "anchor": "art_62", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All’Agenzia si applica il regolamento n. 1 (<span class=\"oj-super oj-note-tag\">27</span>) del Consiglio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le decisioni prese in base all’articolo 342 TFUE, la relazione annuale consolidata relativa alle attività dell’Agenzia e i documenti di programmazione di cui all’articolo 42 sono redatti in tutte le lingue ufficiali delle istituzioni dell’Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il Centro di traduzione degli organismi dell’Unione europea fornisce i servizi di traduzione necessari per il funzionamento dell’Agenzia.</p>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "Trasparenza", "anchor": "art_63", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai documenti in possesso dell’Agenzia si applica il regolamento (CE) n. 1049/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia può comunicare informazioni di propria iniziativa sulle questioni che rientrano nell’ambito dei suoi compiti. L’Agenzia rende pubblica la relazione annuale consolidata relativa alle attività dell’Agenzia e garantisce, in particolare, che il pubblico e qualsiasi parte interessata possano disporre rapidamente di informazioni obiettive, affidabili e facilmente comprensibili riguardanti la sua attività.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio d’amministrazione, entro sei mesi dalla data della sua prima riunione, adotta le modalità di applicazione dei paragrafi 1 e 2.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualsiasi persona fisica o giuridica ha il diritto di rivolgersi per iscritto all’Agenzia in una delle lingue ufficiali delle istituzioni dell’Unione. Ha inoltre diritto di ricevere una risposta nella medesima lingua.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le decisioni adottate dall’Agenzia ai sensi dell’articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore europeo o di ricorso dinanzi alla CGUE alle condizioni stabilite, rispettivamente, agli articoli 228 e 263 TFUE.</p>\n</div>"]]}, "64": {"label": "Articolo 64", "heading": "Lotta antifrode", "anchor": "art_64", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per contrastare le frodi, la corruzione e altre attività illecite si applica senza restrizioni il regolamento (UE, Euratom) n. 883/2013. L’Agenzia aderisce all’accordo interistituzionale del 25 maggio 1999 relativo alle indagini interne svolte dall’OLAF e adotta le opportune disposizioni applicabili a tutti i propri dipendenti utilizzando i modelli riportati nell’allegato di tale accordo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte dei conti ha il potere di revisione contabile, esercitabile sulla base di documenti e di controlli e verifiche sul posto, su tutti i beneficiari di sovvenzioni, contraenti e subcontraenti che hanno ottenuto finanziamenti dell’Unione da parte dell’Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’OLAF può svolgere indagini, compresi controlli e verifiche sul posto, conformemente alle disposizioni e procedure stabilite dal regolamento (UE, Euratom) n. 883/2013 e dal regolamento (Euratom, CE) n. 2185/96 (<span class=\"oj-super oj-note-tag\">28</span>) per accertare eventuali frodi, casi di corruzione o altre attività illecite lesive degli interessi finanziari dell’Unione in relazione a convenzioni o decisioni di sovvenzione o a contratti finanziati dall’Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatti salvi i paragrafi 1, 2 e 3, gli accordi operativi con paesi terzi e organizzazioni internazionali, i contratti, le convenzioni di sovvenzione e le decisioni di sovvenzione dell’Agenzia contengono disposizioni che autorizzano esplicitamente la Corte dei conti e l’OLAF a procedere a tali revisioni contabili e indagini conformemente alle loro rispettive competenze.</p>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Regime di sicurezza in materia di protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_65", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Agenzia applica le norme di sicurezza della Commissione di cui alle decisioni (UE, Euratom) 2015/443 (<span class=\"oj-super oj-note-tag\">29</span>) e (UE, Euratom) 2015/444 della Commissione. Tali norme si applicano, in particolare, allo scambio, al trattamento e alla conservazione di informazioni classificate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’Agenzia applica i principi di sicurezza adottati in relazione al trattamento delle informazioni sensibili non classificate quali definiti nelle decisioni (UE, Euratom) 2015/443 e (UE, Euratom) 2015/444 e attuati dalla Commissione. Il consiglio d’amministrazione stabilisce le modalità di applicazione di tali principi di sicurezza.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La classificazione non preclude la trasmissione delle informazioni al Parlamento europeo. Le informazioni e i documenti inviati al Parlamento europeo a norma del presente regolamento sono trasmessi e trattati conformemente alle norme concernenti la trasmissione e il trattamento delle informazioni classificate applicabili tra il Parlamento europeo e la Commissione.</p>\n</div>"]]}, "66": {"label": "Articolo 66", "heading": "Responsabilità", "anchor": "art_66", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La responsabilità contrattuale dell’Agenzia è disciplinata dalla normativa applicabile al contratto di cui trattasi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La CGUE è competente a giudicare in virtù di clausole compromissorie contenute in un contratto concluso dall’Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In materia di responsabilità extracontrattuale l’Agenzia risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dal suo personale nell’esercizio delle loro funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La CGUE è competente a pronunciarsi in merito alle controversie relative al risarcimento dei danni di cui al paragrafo 3.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La responsabilità individuale del personale dell’Agenzia verso l’Agenzia stessa è disciplinata dalle disposizioni dello statuto dei funzionari e del regime applicabile ad esso applicabili.</p>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Monitoraggio amministrativo", "anchor": "art_67", "frags": [[null, "<p class=\"oj-normal\">Le attività dell’Agenzia sono soggette alle indagini del Mediatore europeo ai sensi dell’articolo 228 TFUE.</p>"]]}, "68": {"label": "Articolo 68", "heading": "Accordo di sede e condizioni operative", "anchor": "art_68", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le necessarie disposizioni concernenti l’insediamento dell’Agenzia nello Stato membro in cui l’Agenzia ha sede, le strutture che questo deve mettere a disposizione e le norme specifiche applicabili in tale Stato membro ai membri del consiglio d’amministrazione, al personale dell’Agenzia e ai familiari, sono fissate in un accordo di sede fra l’Agenzia e tale Stato membro. L’accordo di sede è concluso previa approvazione del consiglio d’amministrazione</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Lo Stato membro in cui l’Agenzia ha sede garantisce all’Agenzia le condizioni necessarie per il suo buon funzionamento, offrendo anche una scolarizzazione multilingue e a orientamento europeo, e adeguati collegamenti di trasporto.</p>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Relazione annuale sulla situazione dell’asilo nell’Unione", "anchor": "art_69", "frags": [[null, "<p class=\"oj-normal\">L’Agenzia elabora una relazione annuale sulla situazione dell’asilo nell’Unione. L’Agenzia trasmette la suddetta relazione al consiglio d’amministrazione, al Parlamento europeo, al Consiglio e alla Commissione e il direttore esecutivo la presenta al Parlamento europeo. La relazione annuale sulla situazione dell’asilo nell’Unione è resa pubblica.</p>"]]}, "70": {"label": "Articolo 70", "heading": "Valutazione e riesame", "anchor": "art_70", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Tre mesi dopo la sostituzione del regolamento (UE) n. 604/2013, la Commissione riferisce al Parlamento europeo e al Consiglio in merito ai risultati della sua valutazione circa la necessità di modificare il presente regolamento al fine di garantire la coerenza e l’uniformità interna del quadro giuridico dell’Unione, in particolare per quanto riguarda le disposizioni relative al meccanismo di monitoraggio di cui all’articolo 14, e presenta le proposte necessarie per modificare opportunamente il presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 20 gennaio 2025, e successivamente ogni cinque anni, la Commissione ordina una valutazione esterna indipendente per esaminare, in particolare, i risultati dell’Agenzia in relazione ai suoi obiettivi, al suo mandato e ai suoi compiti. Tale valutazione concerne l’impatto dell’Agenzia sulla cooperazione pratica nelle questioni attinenti all’asilo e sull’agevolazione dell’attuazione del CEAS. La valutazione tiene debitamente conto dei progressi conseguiti nell’ambito del mandato dell’Agenzia, inclusa una valutazione circa la necessità di misure supplementari per assicurare un’effettiva solidarietà e condivisione di responsabilità con gli Stati membri soggetti a particolari pressioni.</p>\n<p class=\"oj-normal\">La valutazione di cui al primo comma affronta in particolare l’eventuale necessità di modificare il mandato dell’Agenzia, e le conseguenze finanziarie di tale modifica. Esamina altresì l’adeguatezza della struttura di gestione all’adempimento dei compiti. La valutazione tiene conto dei pareri delle parti interessate sia a livello dell’Unione sia a livello nazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione trasmette la relazione con i risultati della valutazione di cui al paragrafo 2, corredata delle proprie conclusioni al riguardo, al Parlamento europeo, al Consiglio e al consiglio d’amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ogni due valutazioni di cui al paragrafo 2, la Commissione esamina se sia giustificato mantenere l’Agenzia tenuto conto dei suoi obiettivi, del suo mandato e dei suoi compiti, e può proporre che il presente regolamento venga modificato di conseguenza o abrogato.</p>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Disposizioni transitorie", "anchor": "art_71", "frags": [[null, "<p class=\"oj-normal\">L’Agenzia sostituisce l’EASO per quanto riguarda diritti di proprietà, accordi, obblighi giuridici, contratti di lavoro, impegni finanziari e passività. In particolare, il presente regolamento non incide sui diritti e sugli obblighi del personale dell’EASO, per il quale la continuità della carriera è assicurata sotto tutti gli aspetti.</p>"]]}, "72": {"label": "Articolo 72", "heading": "Sostituzione e abrogazione", "anchor": "art_72", "frags": [[null, "<p class=\"oj-normal\">Il regolamento (UE) n. 439/2010 è sostituito per quanto riguarda gli Stati membri vincolati dal presente regolamento. Pertanto, il regolamento (UE) n. 439/2010 è abrogato.</p>"], [null, "<p class=\"oj-normal\">Per quanto riguarda gli Stati membri vincolati dal presente regolamento, i riferimenti al regolamento abrogato si intendono fatti al presente regolamento e sono da leggersi secondo la tavola di concordanza figurante all’allegato II.</p>"]]}, "73": {"label": "Articolo 73", "heading": "Entrata in vigore", "anchor": "art_73", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"oj-normal\">L’articolo 2, paragrafo 1, lettera q), l’articolo 14 e l’articolo 15, paragrafi 1, 2 e 3, si applicano a decorrere dal 31 dicembre 2023; l’articolo 15, paragrafi da 4 a 8, e l’articolo 22 si applicano a decorrere dalla data nella quale il regolamento (UE) n. 604/2013 viene sostituito, a meno che tale regolamento sia sostituito prima del 31 dicembre 2023, nel qual caso tali disposizioni si applicano a decorrere dal 31 dicembre 2023.</p>"]]}}, "recitals": {}};